{
  "name": "SafetyLink: Construction Safety Management",
  "description": "A comprehensive construction site safety management tool for workers and administrators to manage documents, safety inspections, and site data.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type UserRole = 'Worker' | 'Admin';

export interface User {
  id: string;
  name: string;
  role: UserRole;
  email: string;
}

export interface UploadedFile {
  id: string;
  name: string;
  type: string;
  size: number;
  uploadedAt: string;
  url: string;
}

export interface SiteCategory {
  id: string;
  name: string;
  files: UploadedFile[];
}

export interface ConstructionSite {
  id: string;
  name: string;
  manager: string;
  supervisor: string;
  categories: SiteCategory[];
}

export const DEFAULT_CATEGORIES = [
  'GSA', 'GSB', 'GSC', 'GSD', 'GSE', 'GEF', 'GSG', 
  '현장 안전 점검', '위험발굴/작업중지'
];

export const INITIAL_SITES = [
  {
    id: '1',
    name: '서울 강남구 테헤란로 현장',
    manager: '김철수',
    supervisor: '이영희',
    categories: DEFAULT_CATEGORIES.map(name => ({ id: Math.random().toString(36).substr(2, 9), name, files: [] }))
  },
  {
    id: '2',
    name: '부산 해운대구 주상복합 건설',
    manager: '박지성',
    supervisor: '최민수',
    categories: DEFAULT_CATEGORIES.map(name => ({ id: Math.random().toString(36).substr(2, 9), name, files: [] }))
  }
];

import { GoogleGenAI } from "@google/genai";

export const analyzeSafetyImage = async (base64Image: string, mimeType: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Image, mimeType } },
          { text: "이 건설 현장 사진에서 안전 규정 위반이나 위험 요소를 찾아주세요. 한국어로 요약해줘." }
        ]
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini analysis failed:", error);
    return "AI 분석을 수행할 수 없습니다.";
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { User, UserRole, ConstructionSite, SiteCategory, UploadedFile } from './types';
import { INITIAL_SITES, DEFAULT_CATEGORIES } from './constants';
import { 
  Plus, 
  ChevronRight, 
  FileUp, 
  HardHat, 
  ShieldAlert, 
  User as UserIcon, 
  LogOut, 
  Building2, 
  Search,
  CheckCircle2,
  AlertTriangle,
  X,
  FileText,
  Image as ImageIcon,
  FileSpreadsheet
} from 'lucide-react';

// --- Authentication UI ---
const AuthPage: React.FC<{ onLogin: (user: User) => void }> = ({ onLogin }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [role, setRole] = useState<UserRole>('Worker');
  const [email, setEmail] = useState('');
  const [name, setName] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onLogin({
      id: Math.random().toString(36).substr(2, 9),
      name: name || (role === 'Admin' ? '관리자' : '근로자'),
      role,
      email
    });
  };

  return (
    <div className="min-h-screen bg-slate-900 flex flex-col justify-center px-6">
      <div className="text-center mb-10">
        <div className="inline-flex items-center justify-center p-4 bg-orange-500 rounded-3xl mb-4 shadow-lg shadow-orange-500/30">
          <HardHat size={48} className="text-white" />
        </div>
        <h1 className="text-3xl font-bold text-white tracking-tight">SafetyLink</h1>
        <p className="text-slate-400 mt-2">안전한 건설 현장을 위한 통합 솔루션</p>
      </div>

      <div className="bg-white rounded-3xl p-8 shadow-2xl">
        <div className="flex bg-slate-100 p-1 rounded-xl mb-6">
          <button 
            onClick={() => setIsRegistering(false)}
            className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${!isRegistering ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500'}`}
          >
            로그인
          </button>
          <button 
            onClick={() => setIsRegistering(true)}
            className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${isRegistering ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500'}`}
          >
            회원가입
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          {isRegistering && (
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1 ml-1">계정 유형</label>
              <div className="grid grid-cols-2 gap-3">
                <button 
                  type="button"
                  onClick={() => setRole('Worker')}
                  className={`py-3 px-4 rounded-xl border-2 flex flex-col items-center gap-1 transition-all ${role === 'Worker' ? 'border-orange-500 bg-orange-50' : 'border-slate-200'}`}
                >
                  <UserIcon size={20} className={role === 'Worker' ? 'text-orange-600' : 'text-slate-400'} />
                  <span className={`text-xs font-bold ${role === 'Worker' ? 'text-orange-700' : 'text-slate-600'}`}>근로자용</span>
                </button>
                <button 
                  type="button"
                  onClick={() => setRole('Admin')}
                  className={`py-3 px-4 rounded-xl border-2 flex flex-col items-center gap-1 transition-all ${role === 'Admin' ? 'border-orange-500 bg-orange-50' : 'border-slate-200'}`}
                >
                  <ShieldAlert size={20} className={role === 'Admin' ? 'text-orange-600' : 'text-slate-400'} />
                  <span className={`text-xs font-bold ${role === 'Admin' ? 'text-orange-700' : 'text-slate-600'}`}>관리자용</span>
                </button>
              </div>
            </div>
          )}

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1 ml-1">이메일</label>
            <input 
              type="email" 
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 transition-all"
              placeholder="example@company.com"
              required
            />
          </div>

          {isRegistering && (
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1 ml-1">이름</label>
              <input 
                type="text" 
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 transition-all"
                placeholder="홍길동"
                required
              />
            </div>
          )}

          <button 
            type="submit"
            className="w-full py-4 bg-orange-500 text-white rounded-xl font-bold shadow-lg shadow-orange-500/20 hover:bg-orange-600 active:scale-[0.98] transition-all mt-4"
          >
            {isRegistering ? '계정 생성하기' : '로그인'}
          </button>
        </form>
      </div>
    </div>
  );
};

// --- Components ---
const FileIcon: React.FC<{ type: string }> = ({ type }) => {
  if (type.includes('image')) return <ImageIcon size={20} className="text-blue-500" />;
  if (type.includes('sheet') || type.includes('excel') || type.includes('csv')) return <FileSpreadsheet size={20} className="text-green-600" />;
  return <FileText size={20} className="text-slate-400" />;
};

const AddSiteModal: React.FC<{ isOpen: boolean; onClose: () => void; onAdd: (site: Partial<ConstructionSite>) => void }> = ({ isOpen, onClose, onAdd }) => {
  const [formData, setFormData] = useState({ name: '', manager: '', supervisor: '' });

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4 bg-black/60 backdrop-blur-sm">
      <div className="w-full max-w-lg bg-white rounded-t-3xl sm:rounded-3xl p-6 sm:p-8 animate-in slide-in-from-bottom duration-300">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-bold text-slate-900">새로운 현장 등록</h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
            <X size={24} className="text-slate-400" />
          </button>
        </div>

        <div className="space-y-4">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">현장명</label>
            <input 
              type="text" 
              className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:outline-none"
              placeholder="예: 강남 테헤란로 재개발 현장"
              value={formData.name}
              onChange={(e) => setFormData({ ...formData, name: e.target.value })}
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">현장소장 이름</label>
            <input 
              type="text" 
              className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:outline-none"
              placeholder="이름 입력"
              value={formData.manager}
              onChange={(e) => setFormData({ ...formData, manager: e.target.value })}
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">관리감독자 이름</label>
            <input 
              type="text" 
              className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:outline-none"
              placeholder="이름 입력"
              value={formData.supervisor}
              onChange={(e) => setFormData({ ...formData, supervisor: e.target.value })}
            />
          </div>
        </div>

        <button 
          onClick={() => {
            if (formData.name && formData.manager && formData.supervisor) {
              onAdd(formData);
              setFormData({ name: '', manager: '', supervisor: '' });
              onClose();
            }
          }}
          className="w-full py-4 bg-orange-500 text-white rounded-xl font-bold mt-8 hover:bg-orange-600 active:scale-95 transition-all shadow-lg shadow-orange-500/20"
        >
          등록 완료
        </button>
      </div>
    </div>
  );
};

// --- Main Application ---
export default function App() {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [sites, setSites] = useState<ConstructionSite[]>(INITIAL_SITES);
  const [selectedSiteId, setSelectedSiteId] = useState<string | null>(null);
  const [selectedCategoryId, setSelectedCategoryId] = useState<string | null>(null);
  const [isAddSiteModalOpen, setIsAddSiteModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Auto-login for dev if needed, otherwise leave null
  useEffect(() => {
    // setCurrentUser({ id: '1', name: '김현장', role: 'Admin', email: 'admin@safety.com' });
  }, []);

  const handleAddSite = (siteData: Partial<ConstructionSite>) => {
    const newSite: ConstructionSite = {
      id: Math.random().toString(36).substr(2, 9),
      name: siteData.name || '새 현장',
      manager: siteData.manager || '미지정',
      supervisor: siteData.supervisor || '미지정',
      categories: DEFAULT_CATEGORIES.map(name => ({
        id: Math.random().toString(36).substr(2, 9),
        name,
        files: []
      }))
    };
    setSites(prev => [...prev, newSite]);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, categoryId: string) => {
    const files = e.target.files;
    if (!files || !selectedSiteId) return;

    const newFiles: UploadedFile[] = Array.from(files).map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      type: file.type,
      size: file.size,
      uploadedAt: new Date().toLocaleString(),
      url: URL.createObjectURL(file)
    }));

    setSites(prev => prev.map(site => {
      if (site.id !== selectedSiteId) return site;
      return {
        ...site,
        categories: site.categories.map(cat => {
          if (cat.id !== categoryId) return cat;
          return { ...cat, files: [...cat.files, ...newFiles] };
        })
      };
    }));
  };

  const handleDeleteFile = (siteId: string, categoryId: string, fileId: string) => {
    setSites(prev => prev.map(site => {
      if (site.id !== siteId) return site;
      return {
        ...site,
        categories: site.categories.map(cat => {
          if (cat.id !== categoryId) return cat;
          return { ...cat, files: cat.files.filter(f => f.id !== fileId) };
        })
      };
    }));
  };

  if (!currentUser) {
    return <AuthPage onLogin={setCurrentUser} />;
  }

  const selectedSite = sites.find(s => s.id === selectedSiteId);
  const selectedCategory = selectedSite?.categories.find(c => c.id === selectedCategoryId);

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 overflow-hidden">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between z-10 shrink-0">
        <div className="flex items-center gap-2">
          {selectedSiteId && (
            <button 
              onClick={() => {
                if (selectedCategoryId) setSelectedCategoryId(null);
                else setSelectedSiteId(null);
              }}
              className="mr-2 p-1 hover:bg-slate-100 rounded-lg transition-colors"
            >
              <X size={20} className="text-slate-500" />
            </button>
          )}
          <h1 className="text-xl font-bold text-slate-900 tracking-tight">
            {selectedCategory ? selectedCategory.name : selectedSite ? selectedSite.name : 'SafetyLink'}
          </h1>
        </div>
        <div className="flex items-center gap-3">
          <div className="hidden sm:flex flex-col items-end">
            <span className="text-xs font-bold text-orange-600">{currentUser.role === 'Admin' ? '관리자' : '근로자'}</span>
            <span className="text-sm font-semibold">{currentUser.name}</span>
          </div>
          <button 
            onClick={() => setCurrentUser(null)}
            className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400 hover:text-red-500"
          >
            <LogOut size={20} />
          </button>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto pb-24">
        {!selectedSiteId ? (
          /* Dashboard / Site List */
          <div className="p-6 max-w-2xl mx-auto space-y-6">
            <div className="relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="현장 이름 검색..." 
                className="w-full pl-11 pr-4 py-4 bg-white border border-slate-200 rounded-2xl shadow-sm focus:ring-2 focus:ring-orange-500 focus:outline-none transition-all"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>

            <div className="flex items-center justify-between mb-2">
              <h2 className="text-sm font-bold text-slate-500 uppercase tracking-wider">나의 현장</h2>
              <button 
                onClick={() => setIsAddSiteModalOpen(true)}
                className="flex items-center gap-1 text-orange-600 font-bold text-sm hover:underline"
              >
                <Plus size={16} /> 현장 추가
              </button>
            </div>

            <div className="grid gap-4">
              {sites
                .filter(s => s.name.toLowerCase().includes(searchTerm.toLowerCase()))
                .map(site => (
                  <button 
                    key={site.id}
                    onClick={() => setSelectedSiteId(site.id)}
                    className="flex items-center justify-between p-5 bg-white border border-slate-200 rounded-2xl shadow-sm hover:border-orange-500 hover:shadow-md transition-all group"
                  >
                    <div className="flex items-center gap-4 text-left">
                      <div className="p-3 bg-slate-100 rounded-xl group-hover:bg-orange-50 transition-colors">
                        <Building2 size={24} className="text-slate-600 group-hover:text-orange-600" />
                      </div>
                      <div>
                        <h3 className="font-bold text-slate-900 group-hover:text-orange-700">{site.name}</h3>
                        <p className="text-xs text-slate-500 mt-0.5">소장: {site.manager} | 감독: {site.supervisor}</p>
                      </div>
                    </div>
                    <ChevronRight size={20} className="text-slate-300 group-hover:text-orange-500 transition-colors" />
                  </button>
                ))
              }
              {sites.length === 0 && (
                <div className="text-center py-12 bg-white rounded-3xl border border-dashed border-slate-300">
                  <p className="text-slate-400">등록된 현장이 없습니다.</p>
                </div>
              )}
            </div>
          </div>
        ) : !selectedCategoryId ? (
          /* Site Detail / Categories List */
          <div className="p-6 max-w-2xl mx-auto">
            <div className="bg-orange-500 rounded-3xl p-6 text-white mb-8 shadow-xl shadow-orange-500/20">
              <div className="flex items-center gap-2 mb-1">
                <Building2 size={16} className="opacity-80" />
                <span className="text-xs font-bold uppercase tracking-widest opacity-80">현장 정보</span>
              </div>
              <h2 className="text-2xl font-bold mb-4">{selectedSite?.name}</h2>
              <div className="grid grid-cols-2 gap-4">
                <div className="bg-white/10 p-3 rounded-2xl backdrop-blur-md">
                  <p className="text-[10px] font-bold uppercase opacity-70">현장 소장</p>
                  <p className="font-bold text-sm">{selectedSite?.manager}</p>
                </div>
                <div className="bg-white/10 p-3 rounded-2xl backdrop-blur-md">
                  <p className="text-[10px] font-bold uppercase opacity-70">관리 감독자</p>
                  <p className="font-bold text-sm">{selectedSite?.supervisor}</p>
                </div>
              </div>
            </div>

            <div className="grid gap-3">
              {selectedSite?.categories.map((category) => (
                <button 
                  key={category.id}
                  onClick={() => setSelectedCategoryId(category.id)}
                  className="flex items-center justify-between p-4 bg-white border border-slate-200 rounded-2xl hover:border-orange-500 hover:bg-orange-50/30 transition-all group"
                >
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-slate-50 rounded-lg group-hover:bg-orange-100">
                      <FileUp size={20} className="text-slate-500 group-hover:text-orange-600" />
                    </div>
                    <span className="font-semibold text-slate-800">{category.name}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    {category.files.length > 0 && (
                      <span className="bg-slate-100 text-slate-500 text-[10px] font-bold px-2 py-1 rounded-full">
                        {category.files.length}개 파일
                      </span>
                    )}
                    <ChevronRight size={18} className="text-slate-300 group-hover:text-orange-500" />
                  </div>
                </button>
              ))}
            </div>
          </div>
        ) : (
          /* Category View / File Manager */
          <div className="p-6 max-w-2xl mx-auto space-y-6">
            <div className="bg-white border border-slate-200 rounded-3xl p-6 shadow-sm">
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-lg font-bold text-slate-900">파일 보관함</h2>
                <div className="flex gap-2">
                  <label className="flex items-center gap-2 px-4 py-2 bg-orange-500 text-white text-sm font-bold rounded-xl cursor-pointer hover:bg-orange-600 transition-colors shadow-lg shadow-orange-500/20 active:scale-95">
                    <Plus size={18} /> 파일 추가
                    <input 
                      type="file" 
                      multiple 
                      className="hidden" 
                      onChange={(e) => handleFileUpload(e, selectedCategoryId)}
                    />
                  </label>
                </div>
              </div>

              <div className="space-y-3">
                {selectedCategory?.files.length === 0 ? (
                  <div className="text-center py-10 border-2 border-dashed border-slate-200 rounded-2xl">
                    <FileUp size={40} className="mx-auto text-slate-200 mb-2" />
                    <p className="text-slate-400 text-sm">업로드된 파일이 없습니다.</p>
                  </div>
                ) : (
                  selectedCategory?.files.map(file => (
                    <div 
                      key={file.id}
                      className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100 hover:border-slate-200 transition-colors"
                    >
                      <div className="flex items-center gap-3 min-w-0">
                        <div className="p-2 bg-white rounded-lg shadow-sm">
                          <FileIcon type={file.type} />
                        </div>
                        <div className="min-w-0">
                          <p className="text-sm font-bold text-slate-900 truncate">{file.name}</p>
                          <p className="text-[10px] text-slate-500 font-medium">{file.uploadedAt} • {(file.size / 1024).toFixed(1)}KB</p>
                        </div>
                      </div>
                      <div className="flex gap-2 shrink-0">
                        <a 
                          href={file.url} 
                          target="_blank" 
                          rel="noreferrer" 
                          className="p-2 text-slate-400 hover:text-orange-500 hover:bg-orange-50 rounded-lg transition-colors"
                        >
                          <ChevronRight size={18} />
                        </a>
                        <button 
                          onClick={() => handleDeleteFile(selectedSiteId, selectedCategoryId, file.id)}
                          className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                        >
                          <X size={18} />
                        </button>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>

            {/* AI Safety Tip (Optional Visual Aid) */}
            <div className="bg-indigo-600 rounded-3xl p-6 text-white shadow-xl shadow-indigo-500/20">
              <div className="flex items-center gap-2 mb-3">
                <AlertTriangle size={20} className="text-yellow-300" />
                <h3 className="font-bold">안전 가이드라인</h3>
              </div>
              <p className="text-sm text-indigo-100 leading-relaxed">
                모든 업로드된 사진은 AI를 통해 실시간 안전 위반 검사를 진행할 수 있습니다. 
                특히 <strong>{selectedCategory?.name}</strong> 관련 서류는 최신 양식을 준수해 주세요.
              </p>
            </div>
          </div>
        )}
      </main>

      {/* Bottom Navigation (Mobile Feel) */}
