              <div className="p-2 bg-slate-50 rounded-lg h-fit">
                <FileIcon type={f.type} />
              </div>
              <div>
                <p className="text-sm font-bold text-slate-800 leading-tight mb-1">{f.name}</p>
                <p className="text-xs text-slate-500">{f.uploadedAt}</p>
              </div>
            </div>
          ))}
          {sites.every(s => s.categories.every(c => c.files.length === 0)) && (
            <p className="text-sm text-slate-400 italic">최근 업데이트된 파일이 없습니다.</p>
          )}
        </div>
        <div className="mt-auto pt-8 border-t border-slate-100">
          <div className="bg-slate-50 p-4 rounded-2xl">
            <h4 className="text-xs font-bold text-slate-900 mb-2">오늘의 안전 점검 완료율</h4>
            <div className="w-full bg-slate-200 h-2 rounded-full overflow-hidden">
              <div className="bg-orange-500 h-full w-[65%] rounded-full"></div>
            </div>
            <p className="text-[10px] font-bold text-slate-500 mt-2 text-right">65% 완료</p>
          </div>
        </div>
      </aside>

      {/* Modal */}
      <AddSiteModal 
        isOpen={isAddSiteModalOpen} 
        onClose={() => setIsAddSiteModalOpen(false)} 
        onAdd={handleAddSite} 
      />
    </div>
  );
}

