    const newSite: ConstructionSite = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      manager,
      supervisor,
      categories: DEFAULT_CATEGORIES.map(catName => ({
        id: Math.random().toString(36).substr(2, 9),
        name: catName,
        files: []
      }))
    };
    setSites([...sites, newSite]);
    setActiveSiteId(newSite.id);
    setView('SITES');
