    const newFiles: UploadedFile[] = Array.from(files).map((file: File) => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      type: file.type,
      size: file.size,
      uploadedAt: new Date().toLocaleString(),
      url: URL.createObjectURL(file)
    }));

    setSites(prev => prev.map(site => {
