          if (cat.id !== activeCategoryId) return cat;
          return { ...cat, files: [...cat.files, ...newFiles] };
        })
      };
    }));
  };

  const deleteFile = (fileId: string) => {
    setSites(prev => prev.map(site => {
      if (site.id !== activeSiteId) return site;
      return {
        ...site,
        categories: site.categories.map(cat => {
          if (cat.id !== activeCategoryId) return cat;
