            onClick={() => setIsReg(!isReg)}
            className="w-full text-slate-500 text-sm font-medium py-2"
          >
            {isReg ? '이미 계정이 있으신가요? 로그인' : '계정이 없으신가요? 회원가입'}
          </button>
        </div>
      </div>
    );
  };

  const SiteTabsScreen = () => {
    const currentSite = sites.find(s => s.id === activeSiteId);

    return (
      <div className="flex flex-col h-screen">
