          {/* Tabs Row */}
          <div className="flex overflow-x-auto no-scrollbar gap-6 items-center border-b border-blue-500">
            {sites.map(site => (
              <button
                key={site.id}
                onClick={() => setActiveSiteId(site.id)}
                className={`py-3 px-2 font-bold whitespace-nowrap transition-all relative ${activeSiteId === site.id ? 'text-white' : 'text-blue-200'}`}
              >
                {site.name}
                {activeSiteId === site.id && <div className="absolute bottom-0 left-0 right-0 h-1 bg-white rounded-t-full" />}
