                  <h2 className="text-lg font-bold">{currentSite.name}</h2>
                </div>
                <div className="flex gap-4 text-xs text-slate-500 font-medium">
                  <span>소장: {currentSite.manager}</span>
                  <span>감독: {currentSite.supervisor}</span>
                </div>
              </div>

              <h3 className="px-1 text-sm font-bold text-slate-400 uppercase tracking-widest mb-2">관리 목차</h3>
              {currentSite.categories.map(cat => (
                <button
                  key={cat.id}
                  onClick={() => { setActiveCategoryId(cat.id); setView('CATEGORY_DETAIL'); }}
                  className="w-full flex items-center justify-between p-4 bg-white rounded-2xl shadow-sm border border-slate-100 hover:border-blue-200 hover:bg-blue-50/30 transition-all active:scale-[0.99]"
