        </div>

        <div className="p-6 space-y-6">
          <div className="space-y-4">
            <div>
              <label className="text-xs font-bold text-slate-400 ml-1 uppercase">현장명</label>
              <input 
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:border-blue-500"
                placeholder="현장 이름을 입력하세요"
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
            </div>
            <div>
              <label className="text-xs font-bold text-slate-400 ml-1 uppercase">현장소장</label>
              <input 
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:border-blue-500"
                placeholder="현장소장 이름"
                value={manager}
                onChange={(e) => setManager(e.target.value)}
              />
            </div>
            <div>
              <label className="text-xs font-bold text-slate-400 ml-1 uppercase">관리감독자</label>
              <input 
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:border-blue-500"
                placeholder="관리감독자 이름"
                value={supervisor}
                onChange={(e) => setSupervisor(e.target.value)}
              />
            </div>
          </div>

          <button 
            onClick={() => name && addSite(name, manager, supervisor)}
            className="w-full bg-blue-600 text-white p-4 rounded-xl font-bold shadow-lg shadow-blue-100 active:scale-95 transition-all"
          >
            등록 완료
          </button>
        </div>
      </div>
    );
  };

  const CategoryDetailScreen = () => {
    const site = sites.find(s => s.id === activeSiteId);
    const category = site?.categories.find(c => c.id === activeCategoryId);

    if (!category) return null;

    return (
      <div className="h-screen bg-slate-50 flex flex-col">
        <div className="bg-white border-b border-slate-100 p-4 flex items-center justify-between shrink-0">
          <div className="flex items-center">
            <button onClick={() => setView('SITES')} className="p-2 -ml-2"><ArrowLeft size={24}/></button>
            <div className="ml-2">
              <h2 className="text-lg font-bold text-slate-900 leading-none">{category.name}</h2>
              <p className="text-[10px] font-bold text-blue-600 mt-1 uppercase tracking-wider">{site?.name}</p>
            </div>
          </div>
          <label className="bg-blue-600 text-white p-2 rounded-xl shadow-lg shadow-blue-100 cursor-pointer active:scale-90 transition-all">
            <Plus size={24} />
            <input type="file" multiple className="hidden" onChange={handleFileUpload} />
          </label>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {category.files.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300">
              <FileUp size={64} className="mb-4 opacity-20" />
              <p className="font-medium">업로드된 파일이 없습니다.</p>
              <p className="text-xs mt-1">상단의 + 버튼을 눌러 파일을 추가하세요.</p>
            </div>
          ) : (
            category.files.map(file => (
              <div key={file.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
                <div className="flex items-center gap-3 overflow-hidden">
                  <div className="shrink-0 p-2 bg-slate-100 rounded-lg">
                    {file.type.includes('image') ? <ImageIcon size={20} className="text-blue-500" /> : <FileText size={20} className="text-slate-400" />}
                  </div>
                  <div className="overflow-hidden">
                    <p className="text-sm font-bold text-slate-800 truncate">{file.name}</p>
                    <p className="text-[10px] text-slate-500">{file.uploadedAt} • {(file.size / 1024).toFixed(1)}KB</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <a href={file.url} target="_blank" rel="noreferrer" className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg">
                    <ChevronRight size={18} />
                  </a>
                  <button onClick={() => deleteFile(file.id)} className="p-2 text-slate-300 hover:text-red-500 rounded-lg">
                    <X size={18} />
                  </button>
                </div>
              </div>
            ))
          )}
        </div>

        {/* Floating Upload Hint for empty screen */}
        {category.files.length > 0 && (
          <div className="px-6 pb-8 pt-4">
             <label className="w-full bg-white border-2 border-dashed border-slate-200 p-4 rounded-2xl flex items-center justify-center gap-2 text-slate-400 cursor-pointer hover:border-blue-400 hover:text-blue-500 transition-all">
                <FileUp size={20} />
                <span className="text-sm font-bold">파일 추가하기</span>
                <input type="file" multiple className="hidden" onChange={handleFileUpload} />
             </label>
          </div>
        )}
      </div>
    );
  };

  // --- Router ---
  if (view === 'AUTH') return <AuthScreen />;
  if (view === 'ADD_SITE') return <AddSiteScreen />;
  if (view === 'CATEGORY_DETAIL') return <CategoryDetailScreen />;

  return <SiteTabsScreen />;
}

export type UserRole = 'Worker' | 'Admin';

export interface User {
  id: string;
  name: string;
  role: UserRole;
  email: string;
}

export interface UploadedFile {
  id: string;
  name: string;
  type: string;
  size: number;
  uploadedAt: string;
  uploadedBy: string;
  uploaderRole: UserRole;
  url: string;
}

export interface SiteCategory {
  id: string;
  name: string;
  files: UploadedFile[];
}

export interface ConstructionSite {
  id: string;
  name: string;
  manager: string;
  supervisor: string;
  categories: SiteCategory[];
}

import React, { useState, useRef } from 'react';
import { User, UserRole, ConstructionSite, SiteCategory, UploadedFile } from './types';
import { INITIAL_SITES, DEFAULT_CATEGORIES } from './constants';
import { 
  Plus, 
  ChevronRight, 
  FileUp, 
  HardHat, 
  ShieldAlert, 
  User as UserIcon, 
  LogOut, 
  Building2, 
  X, 
  FileText, 
  Image as ImageIcon, 
  FileSpreadsheet,
  ArrowLeft,
  Search,
  Check,
  Download,
  Trash2
} from 'lucide-react';

// --- Types of Views ---
type ViewState = 'AUTH' | 'SITES' | 'ADD_SITE' | 'MENU' | 'CATEGORY_DETAIL';

export default function App() {
  // --- State ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('AUTH');
  const [sites, setSites] = useState<ConstructionSite[]>(INITIAL_SITES);
  const [activeSiteId, setActiveSiteId] = useState<string | null>(null);
  const [activeCategoryId, setActiveCategoryId] = useState<string | null>(null);

  // --- Auth Handlers ---
  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setView('SITES');
    if (sites.length > 0) setActiveSiteId(sites[0].id);
  };

  // --- Site Handlers ---
  const addSite = (name: string, manager: string, supervisor: string) => {
    const newSite: ConstructionSite = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      manager,
      supervisor,
      categories: DEFAULT_CATEGORIES.map(catName => ({
        id: Math.random().toString(36).substr(2, 9),
        name: catName,
        files: []
      }))
    };
    setSites([...sites, newSite]);
    setActiveSiteId(newSite.id);
    setView('SITES');
  };

  // --- File Handlers ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || !activeSiteId || !activeCategoryId || !currentUser) return;

    const newFiles: UploadedFile[] = Array.from(files).map((file: File) => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      type: file.type,
      size: file.size,
      uploadedAt: new Date().toLocaleString('ko-KR', { 
        year: 'numeric', month: '2-digit', day: '2-digit', 
        hour: '2-digit', minute: '2-digit' 
      }),
      uploadedBy: currentUser.name,
      uploaderRole: currentUser.role,
      url: URL.createObjectURL(file)
    }));

    setSites(prev => prev.map(site => {
      if (site.id !== activeSiteId) return site;
      return {
        ...site,
        categories: site.categories.map(cat => {
          if (cat.id !== activeCategoryId) return cat;
          return { ...cat, files: [...cat.files, ...newFiles] };
        })
      };
    }));
  };

  const deleteFile = (fileId: string) => {
    setSites(prev => prev.map(site => {
      if (site.id !== activeSiteId) return site;
      return {
        ...site,
        categories: site.categories.map(cat => {
          if (cat.id !== activeCategoryId) return cat;
          return { ...cat, files: cat.files.filter(f => f.id !== fileId) };
        })
      };
    }));
  };

  // --- Sub-Components ---

  const AuthScreen = () => {
    const [isReg, setIsReg] = useState(false);
    const [role, setRole] = useState<UserRole>('Worker');
    const [name, setName] = useState('');

    return (
      <div className="min-h-screen bg-white flex flex-col p-8">
        <div className="mt-20 mb-12 text-center">
          <div className="bg-blue-600 w-20 h-20 rounded-3xl flex items-center justify-center mx-auto shadow-lg mb-6">
            <HardHat size={40} className="text-white" />
          </div>
          <h1 className="text-3xl font-bold text-slate-900">GSS 안전관리</h1>
          <p className="text-slate-500 mt-2 text-sm">건설 현장의 스마트한 관리 파트너</p>
        </div>

        <div className="space-y-4">
          <div className="flex bg-slate-100 p-1 rounded-xl mb-4">
            <button 
              onClick={() => setRole('Worker')}
              className={`flex-1 py-2.5 rounded-lg font-bold text-sm transition-all ${role === 'Worker' ? 'bg-white shadow text-blue-600' : 'text-slate-500'}`}
            >
              근로자용
            </button>
            <button 
              onClick={() => setRole('Admin')}
              className={`flex-1 py-2.5 rounded-lg font-bold text-sm transition-all ${role === 'Admin' ? 'bg-white shadow text-blue-600' : 'text-slate-500'}`}
            >
              관리자용
            </button>
          </div>

          <div className="space-y-3">
            <input 
              type="text" 
              placeholder="이름 (관리자/근로자 성함)" 
              className="w-full p-4 bg-slate-50 rounded-xl border border-slate-200 focus:outline-none focus:border-blue-500 transition-colors"
              value={name}
              onChange={(e) => setName(e.target.value)}
            />
            <input 
              type="password" 
              placeholder="비밀번호" 
              className="w-full p-4 bg-slate-50 rounded-xl border border-slate-200 focus:outline-none focus:border-blue-500 transition-colors"
            />
          </div>

          <button 
            onClick={() => handleLogin({ id: Math.random().toString(36).substr(2, 9), name: name || '사용자', role, email: 'user@gss.com' })}
            className="w-full bg-blue-600 text-white p-4 rounded-xl font-bold shadow-lg shadow-blue-200 active:scale-[0.98] transition-all mt-4"
          >
            {isReg ? '계정 만들기' : '시작하기'}
          </button>

          <button 
            onClick={() => setIsReg(!isReg)}
            className="w-full text-slate-400 text-xs font-medium py-2"
          >
            {isReg ? '이미 계정이 있으신가요? 로그인' : '처음이신가요? 회원가입'}
          </button>
        </div>
      </div>
    );
  };

  const SiteTabsScreen = () => {
    const currentSite = sites.find(s => s.id === activeSiteId);

    return (
      <div className="flex flex-col h-screen bg-slate-50">
        {/* Header */}
        <div className="bg-blue-600 text-white px-4 pt-4 shrink-0 shadow-md">
          <div className="flex justify-between items-center mb-4">
            <div className="flex items-center gap-2">
              <div className="bg-white/20 p-1.5 rounded-lg">
                <HardHat size={18} />
              </div>
              <h1 className="text-lg font-bold">GSS 안전관리</h1>
            </div>
            <div className="flex items-center gap-3">
               <div className="text-right hidden sm:block">
                  <p className="text-[10px] font-bold text-blue-200 leading-none">{currentUser?.role === 'Admin' ? '관리자' : '근로자'}</p>
                  <p className="text-sm font-bold">{currentUser?.name}</p>
               </div>
               <button onClick={() => setCurrentUser(null)} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                 <LogOut size={20}/>
               </button>
            </div>
          </div>

          {/* Tabs Row */}
          <div className="flex overflow-x-auto no-scrollbar gap-6 items-center border-b border-blue-500/50">
            {sites.map(site => (
              <button
                key={site.id}
                onClick={() => setActiveSiteId(site.id)}
                className={`py-3 px-2 font-bold whitespace-nowrap transition-all relative text-sm ${activeSiteId === site.id ? 'text-white' : 'text-blue-200'}`}
              >
                {site.name}
                {activeSiteId === site.id && <div className="absolute bottom-0 left-0 right-0 h-1 bg-white rounded-t-full" />}
              </button>
            ))}
            <button 
              onClick={() => setView('ADD_SITE')}
              className="flex items-center gap-1 py-3 px-2 text-blue-100 font-bold whitespace-nowrap text-sm hover:text-white"
            >
              <Plus size={16} /> 현장 추가
            </button>
          </div>
        </div>

        {/* Site Content (Menu) */}
        <div className="flex-1 overflow-y-auto p-4">
          {currentSite ? (
            <div className="max-w-2xl mx-auto space-y-4">
              <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 mb-6">
                <div className="flex items-center gap-3 mb-3">
                  <div className="p-2 bg-blue-50 rounded-xl">
                    <Building2 className="text-blue-600" size={20} />
                  </div>
                  <div>
                    <h2 className="text-lg font-bold text-slate-900">{currentSite.name}</h2>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">현장 상세 정보</p>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <div className="bg-slate-50 p-3 rounded-xl">
                    <p className="text-[10px] font-bold text-slate-400 mb-1">현장소장</p>
                    <p className="text-sm font-bold text-slate-700">{currentSite.manager}</p>
                  </div>
                  <div className="bg-slate-50 p-3 rounded-xl">
                    <p className="text-[10px] font-bold text-slate-400 mb-1">관리감독자</p>
                    <p className="text-sm font-bold text-slate-700">{currentSite.supervisor}</p>
                  </div>
                </div>
              </div>

              <h3 className="px-1 text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">관리 목차</h3>
              <div className="grid gap-2.5">
                {currentSite.categories.map(cat => (
                  <button
                    key={cat.id}
                    onClick={() => { setActiveCategoryId(cat.id); setView('CATEGORY_DETAIL'); }}
                    className="w-full flex items-center justify-between p-4 bg-white rounded-2xl shadow-sm border border-slate-100 hover:border-blue-300 hover:shadow-md transition-all active:scale-[0.99] group"
                  >
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-slate-50 rounded-lg group-hover:bg-blue-50 transition-colors">
                        <FileText size={20} className="text-slate-400 group-hover:text-blue-600" />
                      </div>
                      <span className="font-bold text-slate-700">{cat.name}</span>
                    </div>
                    <div className="flex items-center gap-2">
                      {cat.files.length > 0 && (
                        <span className="bg-blue-600 text-white text-[10px] font-bold px-2 py-0.5 rounded-full shadow-sm shadow-blue-200">
                          {cat.files.length}
                        </span>
                      )}
                      <ChevronRight size={18} className="text-slate-300 group-hover:text-blue-600 transition-colors" />
                    </div>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 py-20">
              <Building2 size={64} className="mb-4 opacity-10" />
              <p className="font-bold">등록된 현장이 없습니다.</p>
              <button 
                onClick={() => setView('ADD_SITE')}
                className="mt-4 bg-blue-600 text-white px-6 py-3 rounded-xl font-bold shadow-lg shadow-blue-100 active:scale-95 transition-all"
              >
                첫 현장 등록하기
              </button>
            </div>
          )}
        </div>
      </div>
    );
  };

  const AddSiteScreen = () => {
    const [name, setName] = useState('');
    const [manager, setManager] = useState('');
    const [supervisor, setSupervisor] = useState('');

    return (
      <div className="h-screen bg-white flex flex-col">
        <div className="flex items-center p-4 border-b border-slate-100">
          <button onClick={() => setView('SITES')} className="p-2 -ml-2 text-slate-400 hover:text-blue-600 transition-colors">
            <ArrowLeft size={24}/>
          </button>
          <h2 className="text-lg font-bold ml-2 text-slate-800">새로운 현장 등록</h2>
        </div>

        <div className="p-6 space-y-8 max-w-lg mx-auto w-full">
          <div className="space-y-5">
            <div>
              <label className="text-[10px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-1">현장명</label>
              <input 
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 transition-all"
                placeholder="예: 서울 강남 테헤란로 현장"
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
