            <div>
              <label className="text-[10px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-1">현장소장 성함</label>
              <input 
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 transition-all"
                placeholder="이름을 입력하세요"
                value={manager}
                onChange={(e) => setManager(e.target.value)}
              />
            </div>
            <div>
              <label className="text-[10px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-1">관리감독자 성함</label>
              <input 
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 transition-all"
                placeholder="이름을 입력하세요"
                value={supervisor}
                onChange={(e) => setSupervisor(e.target.value)}
              />
            </div>
          </div>

          <button 
            onClick={() => name && addSite(name, manager, supervisor)}
            className="w-full bg-blue-600 text-white p-4 rounded-xl font-bold shadow-xl shadow-blue-200 active:scale-95 transition-all"
          >
            현장 등록 완료
          </button>
        </div>
      </div>
    );
  };

  const CategoryDetailScreen = () => {
    const site = sites.find(s => s.id === activeSiteId);
    const category = site?.categories.find(c => c.id === activeCategoryId);

    if (!category) return null;

    return (
      <div className="h-screen bg-slate-50 flex flex-col">
        {/* Header */}
        <div className="bg-white border-b border-slate-200 p-4 flex items-center justify-between shrink-0 sticky top-0 z-10">
          <div className="flex items-center min-w-0">
            <button onClick={() => setView('SITES')} className="p-2 -ml-2 text-slate-400 hover:text-blue-600 transition-colors">
              <ArrowLeft size={24}/>
            </button>
            <div className="ml-2 min-w-0">
              <h2 className="text-lg font-bold text-slate-900 leading-none truncate">{category.name}</h2>
              <p className="text-[10px] font-bold text-blue-600 mt-1 uppercase tracking-widest truncate">{site?.name}</p>
            </div>
          </div>
          <div className="flex gap-2">
             <label className="bg-blue-600 text-white p-2.5 rounded-xl shadow-lg shadow-blue-200 cursor-pointer active:scale-90 transition-all hover:bg-blue-700">
                <FileUp size={22} />
                <input type="file" multiple className="hidden" onChange={handleFileUpload} />
             </label>
          </div>
        </div>

        {/* File List */}
        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {category.files.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300 py-20">
              <div className="bg-slate-100 p-6 rounded-3xl mb-4">
                <FileUp size={48} className="opacity-20" />
              </div>
              <p className="font-bold text-slate-400">파일이 아직 없습니다</p>
              <p className="text-[11px] mt-1 font-medium text-slate-400">우측 상단의 업로드 버튼을 사용해 보세요</p>
            </div>
          ) : (
            <div className="max-w-2xl mx-auto space-y-3">
              <div className="flex items-center justify-between px-1 mb-1">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">업로드된 파일 ({category.files.length})</span>
              </div>
              {category.files.map(file => (
                <div key={file.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between group hover:border-blue-200 transition-all">
                  <div className="flex items-center gap-3 overflow-hidden">
                    <div className="shrink-0 p-2.5 bg-slate-50 rounded-xl group-hover:bg-blue-50 transition-colors">
                      {file.type.includes('image') ? 
                        <ImageIcon size={20} className="text-blue-500" /> : 
                        file.type.includes('sheet') ? 
                        <FileSpreadsheet size={20} className="text-green-600" /> :
                        <FileText size={20} className="text-slate-400" />
                      }
                    </div>
                    <div className="overflow-hidden">
                      <p className="text-sm font-bold text-slate-800 truncate leading-tight mb-1">{file.name}</p>
                      <div className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
                        <span className="text-[10px] font-bold text-blue-600 bg-blue-50 px-1.5 py-0.5 rounded uppercase">
                          {file.uploaderRole === 'Admin' ? '관리자' : '근로자'}
                        </span>
                        <span className="text-[10px] font-bold text-slate-900">{file.uploadedBy}</span>
                        <span className="text-[10px] text-slate-400">|</span>
                        <span className="text-[10px] text-slate-400 font-medium">{file.uploadedAt}</span>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-1 shrink-0 ml-2">
                    <a 
                      href={file.url} 
                      download={file.name}
                      className="p-2 text-blue-600 hover:bg-blue-50 rounded-xl transition-colors flex items-center gap-1"
                      title="다운로드"
                    >
                      <Download size={18} />
                    </a>
                    {(currentUser?.role === 'Admin' || currentUser?.name === file.uploadedBy) && (
                      <button 
                        onClick={() => deleteFile(file.id)} 
                        className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-colors"
                        title="삭제"
                      >
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Quick Upload Hint at bottom if list is long */}
        {category.files.length > 3 && (
          <div className="px-6 pb-8 pt-4 shrink-0 bg-slate-50/80 backdrop-blur-sm border-t border-slate-200/50">
             <label className="w-full bg-white border-2 border-dashed border-slate-200 p-4 rounded-2xl flex items-center justify-center gap-2 text-slate-400 cursor-pointer hover:border-blue-400 hover:text-blue-600 hover:bg-blue-50 transition-all">
                <FileUp size={20} />
                <span className="text-sm font-bold">새 파일 추가</span>
                <input type="file" multiple className="hidden" onChange={handleFileUpload} />
             </label>
          </div>
        )}
      </div>
    );
  };

  // --- Router ---
  if (view === 'AUTH') return <AuthScreen />;
  if (view === 'ADD_SITE') return <AddSiteScreen />;
  if (view === 'CATEGORY_DETAIL') return <CategoryDetailScreen />;

  return <SiteTabsScreen />;
}

import React, { useState, useRef } from 'react';
import { User, UserRole, ConstructionSite, SiteCategory, UploadedFile } from './types';
import { INITIAL_SITES, DEFAULT_CATEGORIES } from './constants';
import { 
  Plus, 
  ChevronRight, 
  FileUp, 
  ShieldAlert, 
  User as UserIcon, 
  LogOut, 
  Building2, 
  X, 
  FileText, 
  Image as ImageIcon, 
  FileSpreadsheet,
  ArrowLeft,
  Download,
  Trash2,
  CheckCircle2
} from 'lucide-react';

// --- Types of Views ---
type ViewState = 'AUTH' | 'SITES' | 'ADD_SITE' | 'MENU' | 'CATEGORY_DETAIL';

// Using the teal color from the Everscape logo: #0097b2
const PRIMARY_TEAL = 'bg-[#0097b2]';
const TEXT_TEAL = 'text-[#0097b2]';
const BORDER_TEAL = 'border-[#0097b2]';
const LOGO_URL = 'https://raw.githubusercontent.com/t-park/everscape-logo/main/everscape_logo.png'; // Placeholder for the provided image

export default function App() {
  // --- State ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('AUTH');
  const [sites, setSites] = useState<ConstructionSite[]>(INITIAL_SITES);
  const [activeSiteId, setActiveSiteId] = useState<string | null>(null);
  const [activeCategoryId, setActiveCategoryId] = useState<string | null>(null);

  // --- Auth Handlers ---
  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setView('SITES');
    if (sites.length > 0) setActiveSiteId(sites[0].id);
  };

  // --- Site Handlers ---
  const addSite = (name: string, manager: string, supervisor: string) => {
    const newSite: ConstructionSite = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      manager,
      supervisor,
      categories: DEFAULT_CATEGORIES.map(catName => ({
        id: Math.random().toString(36).substr(2, 9),
        name: catName,
        files: []
      }))
    };
    setSites([...sites, newSite]);
    setActiveSiteId(newSite.id);
    setView('SITES');
  };

  // --- File Handlers ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || !activeSiteId || !activeCategoryId || !currentUser) return;

    const newFiles: UploadedFile[] = Array.from(files).map((file: File) => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      type: file.type,
      size: file.size,
      uploadedAt: new Date().toLocaleString('ko-KR', { 
        year: 'numeric', month: '2-digit', day: '2-digit', 
        hour: '2-digit', minute: '2-digit' 
      }),
      uploadedBy: currentUser.name,
      uploaderRole: currentUser.role,
      url: URL.createObjectURL(file)
    }));

    setSites(prev => prev.map(site => {
      if (site.id !== activeSiteId) return site;
      return {
        ...site,
        categories: site.categories.map(cat => {
          if (cat.id !== activeCategoryId) return cat;
          return { ...cat, files: [...cat.files, ...newFiles] };
        })
      };
    }));
  };

  const deleteFile = (fileId: string) => {
    setSites(prev => prev.map(site => {
      if (site.id !== activeSiteId) return site;
      return {
        ...site,
        categories: site.categories.map(cat => {
          if (cat.id !== activeCategoryId) return cat;
          return { ...cat, files: cat.files.filter(f => f.id !== fileId) };
        })
      };
    }));
  };

  // --- Sub-Components ---

  const AuthScreen = () => {
    const [isReg, setIsReg] = useState(false);
    const [role, setRole] = useState<UserRole>('Worker');
    const [name, setName] = useState('');

    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8">
        <div className="w-full max-w-md bg-white rounded-[2.5rem] p-8 shadow-xl shadow-slate-200/50">
          <div className="text-center mb-10">
            {/* Using the user's provided logo image instead of the hard hat */}
            <div className="w-full mb-6 flex justify-center">
              <img 
                src="https://raw.githubusercontent.com/t-park/everscape-logo/main/everscape_logo.png" 
                alt="Everscape Logo" 
                className="h-12 object-contain"
                onError={(e) => {
                  // Fallback if the image fails to load
                  e.currentTarget.src = "https://api.iconify.design/logos:everscale.svg";
                }}
              />
            </div>
            <h1 className="text-2xl font-bold text-slate-900">GSS 안전관리</h1>
            <p className="text-slate-400 mt-1 text-sm">에버스케이프 현장 관리 시스템</p>
          </div>

          <div className="space-y-5">
            {/* Explicit Role Selection as requested */}
            <div>
              <label className="text-[10px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">계정 유형 선택</label>
              <div className="grid grid-cols-2 gap-3">
                <button 
                  onClick={() => setRole('Worker')}
                  className={`flex items-center justify-center gap-2 py-3 rounded-2xl font-bold text-sm transition-all border-2 ${role === 'Worker' ? 'border-[#0097b2] bg-[#f0f9fb] text-[#0097b2]' : 'border-slate-100 bg-slate-50 text-slate-400'}`}
                >
                  <UserIcon size={18} />
                  근로자용
                </button>
                <button 
                  onClick={() => setRole('Admin')}
                  className={`flex items-center justify-center gap-2 py-3 rounded-2xl font-bold text-sm transition-all border-2 ${role === 'Admin' ? 'border-[#0097b2] bg-[#f0f9fb] text-[#0097b2]' : 'border-slate-100 bg-slate-50 text-slate-400'}`}
                >
                  <ShieldAlert size={18} />
                  관리자용
                </button>
              </div>
            </div>

            <div className="space-y-3">
              <div>
                <label className="text-[10px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-1">성함</label>
                <input 
                  type="text" 
                  placeholder="성함을 입력하세요" 
                  className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 focus:outline-none focus:border-[#0097b2] transition-colors"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                />
              </div>
              <div>
                <label className="text-[10px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-1">비밀번호</label>
                <input 
                  type="password" 
                  placeholder="비밀번호를 입력하세요" 
                  className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 focus:outline-none focus:border-[#0097b2] transition-colors"
                />
              </div>
            </div>

            <button 
              onClick={() => handleLogin({ id: Math.random().toString(36).substr(2, 9), name: name || '사용자', role, email: 'user@gss.com' })}
              className="w-full bg-[#0097b2] text-white p-4 rounded-2xl font-bold shadow-lg shadow-[#0097b2]/20 active:scale-[0.98] transition-all mt-4"
            >
              {isReg ? '계정 생성하기' : '로그인'}
            </button>

            <button 
              onClick={() => setIsReg(!isReg)}
              className="w-full text-slate-400 text-xs font-medium py-2"
            >
              {isReg ? '이미 계정이 있으신가요? 로그인' : '처음이신가요? 회원가입'}
            </button>
          </div>
        </div>
      </div>
    );
  };

  const SiteTabsScreen = () => {
    const currentSite = sites.find(s => s.id === activeSiteId);

    return (
      <div className="flex flex-col h-screen bg-slate-50">
        {/* Header */}
        <div className="bg-white text-slate-800 px-4 pt-4 shrink-0 shadow-sm border-b border-slate-100">
          <div className="flex justify-between items-center mb-4">
            <div className="flex items-center gap-2">
              <img 
                src="https://raw.githubusercontent.com/t-park/everscape-logo/main/everscape_logo.png" 
                alt="Logo" 
                className="h-6 object-contain"
                onError={(e) => e.currentTarget.style.display = 'none'}
              />
              <h1 className="text-lg font-bold text-[#0097b2]">GSS 안전관리</h1>
            </div>
            <div className="flex items-center gap-3">
               <div className="text-right hidden sm:block">
                  <p className="text-[10px] font-bold text-slate-400 leading-none">{currentUser?.role === 'Admin' ? '관리자' : '근로자'}</p>
                  <p className="text-sm font-bold text-slate-700">{currentUser?.name}</p>
               </div>
               <button onClick={() => setCurrentUser(null)} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400">
                 <LogOut size={20}/>
               </button>
            </div>
          </div>

          {/* Tabs Row */}
          <div className="flex overflow-x-auto no-scrollbar gap-6 items-center">
            {sites.map(site => (
              <button
                key={site.id}
                onClick={() => setActiveSiteId(site.id)}
                className={`py-3 px-2 font-bold whitespace-nowrap transition-all relative text-sm ${activeSiteId === site.id ? 'text-[#0097b2]' : 'text-slate-400'}`}
              >
                {site.name}
                {activeSiteId === site.id && <div className="absolute bottom-0 left-0 right-0 h-1 bg-[#0097b2] rounded-t-full" />}
              </button>
            ))}
            <button 
              onClick={() => setView('ADD_SITE')}
              className="flex items-center gap-1 py-3 px-2 text-[#0097b2] font-bold whitespace-nowrap text-sm opacity-60 hover:opacity-100"
            >
              <Plus size={16} /> 현장 추가
            </button>
          </div>
        </div>

        {/* Site Content (Menu) */}
        <div className="flex-1 overflow-y-auto p-4">
          {currentSite ? (
            <div className="max-w-2xl mx-auto space-y-4">
              <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 mb-6">
                <div className="flex items-center gap-3 mb-4">
                  <div className="p-3 bg-[#f0f9fb] rounded-2xl">
                    <Building2 className="text-[#0097b2]" size={24} />
                  </div>
                  <div>
                    <h2 className="text-xl font-bold text-slate-900">{currentSite.name}</h2>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">건설 현장 정보</p>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-slate-50 p-4 rounded-2xl">
                    <p className="text-[10px] font-bold text-slate-400 mb-1">현장소장</p>
                    <p className="text-sm font-bold text-slate-700">{currentSite.manager}</p>
                  </div>
                  <div className="bg-slate-50 p-4 rounded-2xl">
                    <p className="text-[10px] font-bold text-slate-400 mb-1">관리감독자</p>
                    <p className="text-sm font-bold text-slate-700">{currentSite.supervisor}</p>
                  </div>
                </div>
              </div>

              <h3 className="px-2 text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">관리 목차</h3>
              <div className="grid gap-3">
                {currentSite.categories.map(cat => (
                  <button
                    key={cat.id}
                    onClick={() => { setActiveCategoryId(cat.id); setView('CATEGORY_DETAIL'); }}
                    className="w-full flex items-center justify-between p-5 bg-white rounded-[1.5rem] shadow-sm border border-slate-100 hover:border-[#0097b2]/30 hover:shadow-md transition-all active:scale-[0.99] group"
                  >
                    <div className="flex items-center gap-4">
                      <div className="p-2.5 bg-slate-50 rounded-xl group-hover:bg-[#f0f9fb] transition-colors">
                        <FileText size={22} className="text-slate-400 group-hover:text-[#0097b2]" />
                      </div>
                      <span className="font-bold text-slate-700">{cat.name}</span>
                    </div>
                    <div className="flex items-center gap-2">
                      {cat.files.length > 0 && (
                        <span className="bg-[#0097b2] text-white text-[10px] font-bold px-2 py-0.5 rounded-full shadow-sm shadow-[#0097b2]/20">
                          {cat.files.length}
                        </span>
                      )}
                      <ChevronRight size={20} className="text-slate-300 group-hover:text-[#0097b2] transition-colors" />
                    </div>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 py-20">
              <Building2 size={64} className="mb-4 opacity-10" />
              <p className="font-bold">등록된 현장이 없습니다.</p>
              <button 
                onClick={() => setView('ADD_SITE')}
                className="mt-6 bg-[#0097b2] text-white px-8 py-4 rounded-2xl font-bold shadow-lg shadow-[#0097b2]/20 active:scale-95 transition-all"
              >
                첫 현장 등록하기
              </button>
            </div>
          )}
        </div>
      </div>
    );
  };

  const AddSiteScreen = () => {
    const [name, setName] = useState('');
    const [manager, setManager] = useState('');
    const [supervisor, setSupervisor] = useState('');

    return (
      <div className="h-screen bg-white flex flex-col">
        <div className="flex items-center p-4 border-b border-slate-100">
          <button onClick={() => setView('SITES')} className="p-2 -ml-2 text-slate-400 hover:text-[#0097b2] transition-colors">
            <ArrowLeft size={24}/>
          </button>
          <h2 className="text-lg font-bold ml-2 text-slate-800">새로운 현장 등록</h2>
        </div>

        <div className="p-6 space-y-8 max-w-lg mx-auto w-full">
          <div className="space-y-5">
            <div>
              <label className="text-[10px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-1">현장명</label>
              <input 
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all"
                placeholder="예: 서울 강남 테헤란로 현장"
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
            </div>
            <div>
              <label className="text-[10px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-1">현장소장 성함</label>
              <input 
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all"
                placeholder="이름을 입력하세요"
                value={manager}
                onChange={(e) => setManager(e.target.value)}
              />
            </div>
            <div>
              <label className="text-[10px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-1">관리감독자 성함</label>
              <input 
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all"
                placeholder="이름을 입력하세요"
                value={supervisor}
                onChange={(e) => setSupervisor(e.target.value)}
              />
            </div>
          </div>

          <button 
            onClick={() => name && addSite(name, manager, supervisor)}
            className="w-full bg-[#0097b2] text-white p-4 rounded-2xl font-bold shadow-xl shadow-[#0097b2]/20 active:scale-95 transition-all"
          >
            현장 등록 완료
          </button>
        </div>
      </div>
    );
  };

  const CategoryDetailScreen = () => {
    const site = sites.find(s => s.id === activeSiteId);
    const category = site?.categories.find(c => c.id === activeCategoryId);

    if (!category) return null;

    return (
      <div className="h-screen bg-slate-50 flex flex-col">
        {/* Header */}
        <div className="bg-white border-b border-slate-200 p-4 flex items-center justify-between shrink-0 sticky top-0 z-10">
          <div className="flex items-center min-w-0">
            <button onClick={() => setView('SITES')} className="p-2 -ml-2 text-slate-400 hover:text-[#0097b2] transition-colors">
              <ArrowLeft size={24}/>
            </button>
            <div className="ml-2 min-w-0">
              <h2 className="text-lg font-bold text-slate-900 leading-none truncate">{category.name}</h2>
              <p className="text-[10px] font-bold text-[#0097b2] mt-1 uppercase tracking-widest truncate">{site?.name}</p>
            </div>
          </div>
          <div className="flex gap-2">
             <label className="bg-[#0097b2] text-white p-2.5 rounded-2xl shadow-lg shadow-[#0097b2]/20 cursor-pointer active:scale-90 transition-all hover:bg-[#008199]">
                <FileUp size={22} />
                <input type="file" multiple className="hidden" onChange={handleFileUpload} />
             </label>
          </div>
        </div>

        {/* File List */}
        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {category.files.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300 py-20">
              <div className="bg-white p-8 rounded-[2.5rem] shadow-sm mb-4">
                <FileUp size={48} className="text-[#0097b2] opacity-30" />
              </div>
              <p className="font-bold text-slate-400">업로드된 파일이 없습니다</p>
              <p className="text-[11px] mt-2 font-medium text-slate-400 bg-slate-100 px-3 py-1 rounded-full">상단 버튼으로 파일을 추가하세요</p>
            </div>
          ) : (
            <div className="max-w-2xl mx-auto space-y-3">
              <div className="flex items-center justify-between px-2 mb-1">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">문서 및 이미지 ({category.files.length})</span>
              </div>
              {category.files.map(file => (
                <div key={file.id} className="bg-white p-4 rounded-[1.5rem] shadow-sm border border-slate-100 flex items-center justify-between group hover:border-[#0097b2]/30 transition-all">
                  <div className="flex items-center gap-3 overflow-hidden">
                    <div className="shrink-0 w-12 h-12 flex items-center justify-center bg-slate-50 rounded-2xl group-hover:bg-[#f0f9fb] transition-colors overflow-hidden border border-slate-50">
                      {file.type.includes('image') ? (
                        <img src={file.url} className="w-full h-full object-cover" alt="Preview" />
                      ) : (
                        file.type.includes('sheet') ? 
                        <FileSpreadsheet size={20} className="text-green-600" /> :
                        <FileText size={20} className="text-slate-400" />
                      )}
                    </div>
                    <div className="overflow-hidden">
                      <p className="text-sm font-bold text-slate-800 truncate leading-tight mb-1.5">{file.name}</p>
                      <div className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
                        <span className="text-[9px] font-bold text-white bg-[#0097b2] px-1.5 py-0.5 rounded uppercase tracking-tighter">
                          {file.uploaderRole === 'Admin' ? '관리자' : '근로자'}
                        </span>
                        <span className="text-[10px] font-bold text-slate-700">{file.uploadedBy}</span>
                        <span className="text-[10px] text-slate-300">•</span>
                        <span className="text-[10px] text-slate-400 font-medium">{file.uploadedAt}</span>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-1 shrink-0 ml-2">
                    <a 
                      href={file.url} 
                      download={file.name}
                      className="p-2 text-[#0097b2] hover:bg-[#f0f9fb] rounded-xl transition-colors flex items-center gap-1"
                      title="다운로드"
                    >
                      <Download size={18} />
                    </a>
                    {(currentUser?.role === 'Admin' || currentUser?.name === file.uploadedBy) && (
                      <button 
                        onClick={() => deleteFile(file.id)} 
                        className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-colors"
                        title="삭제"
                      >
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Quick Upload Hint */}
        <div className="px-6 pb-8 pt-4 shrink-0 bg-slate-50/80 backdrop-blur-sm border-t border-slate-200/50">
           <label className="w-full bg-white border-2 border-dashed border-slate-200 p-4 rounded-[1.5rem] flex items-center justify-center gap-2 text-slate-400 cursor-pointer hover:border-[#0097b2] hover:text-[#0097b2] hover:bg-[#f0f9fb] transition-all">
              <FileUp size={20} />
              <span className="text-sm font-bold">파일 추가 업로드</span>
              <input type="file" multiple className="hidden" onChange={handleFileUpload} />
           </label>
        </div>
      </div>
    );
  };

  // --- Router ---
  if (view === 'AUTH') return <AuthScreen />;
  if (view === 'ADD_SITE') return <AddSiteScreen />;
  if (view === 'CATEGORY_DETAIL') return <CategoryDetailScreen />;

  return <SiteTabsScreen />;
}

import React, { useState } from 'react';
import { User, UserRole, ConstructionSite, SiteCategory, UploadedFile } from './types';
import { INITIAL_SITES, DEFAULT_CATEGORIES } from './constants';
import { 
  Plus, 
  ChevronRight, 
  FileUp, 
  LogOut, 
  Building2, 
  X, 
  FileText, 
  Image as ImageIcon, 
  FileSpreadsheet,
  ArrowLeft,
  Download,
  Trash2,
  ShieldCheck,
  User as UserIcon,
  HardHat
} from 'lucide-react';

// --- Types of Views ---
type ViewState = 'AUTH' | 'SITES' | 'ADD_SITE' | 'MENU' | 'CATEGORY_DETAIL';

// Everscape Teal color: #0097b2
const PRIMARY_TEAL = '#0097b2';
const LOGO_URL = 'https://raw.githubusercontent.com/t-park/everscape-logo/main/everscape_logo.png';

export default function App() {
  // --- State ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('AUTH');
  const [sites, setSites] = useState<ConstructionSite[]>(INITIAL_SITES);
  const [activeSiteId, setActiveSiteId] = useState<string | null>(null);
  const [activeCategoryId, setActiveCategoryId] = useState<string | null>(null);

  // --- Auth Handlers ---
  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setView('SITES');
    if (sites.length > 0) setActiveSiteId(sites[0].id);
  };

  // --- Site Handlers ---
  const addSite = (name: string, manager: string, supervisor: string) => {
    const newSite: ConstructionSite = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      manager,
      supervisor,
      categories: DEFAULT_CATEGORIES.map(catName => ({
        id: Math.random().toString(36).substr(2, 9),
        name: catName,
        files: []
      }))
    };
    setSites([...sites, newSite]);
    setActiveSiteId(newSite.id);
    setView('SITES');
  };

  // --- File Handlers ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || !activeSiteId || !activeCategoryId || !currentUser) return;

    const newFiles: UploadedFile[] = Array.from(files).map((file: File) => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      type: file.type,
      size: file.size,
      uploadedAt: new Date().toLocaleString('ko-KR', { 
        year: 'numeric', month: '2-digit', day: '2-digit', 
        hour: '2-digit', minute: '2-digit' 
      }),
      uploadedBy: currentUser.name,
      uploaderRole: currentUser.role,
      url: URL.createObjectURL(file)
    }));

    setSites(prev => prev.map(site => {
      if (site.id !== activeSiteId) return site;
      return {
        ...site,
        categories: site.categories.map(cat => {
          if (cat.id !== activeCategoryId) return cat;
          return { ...cat, files: [...cat.files, ...newFiles] };
        })
      };
    }));
  };

  const deleteFile = (fileId: string) => {
    setSites(prev => prev.map(site => {
      if (site.id !== activeSiteId) return site;
      return {
        ...site,
        categories: site.categories.map(cat => {
          if (cat.id !== activeCategoryId) return cat;
          return { ...cat, files: cat.files.filter(f => f.id !== fileId) };
        })
      };
    }));
  };

  // --- Sub-Components ---

  const AuthScreen = () => {
    const [isReg, setIsReg] = useState(false);
    const [role, setRole] = useState<UserRole>('Worker');
    const [name, setName] = useState('');

    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
        <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 shadow-2xl shadow-slate-200/60 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-full mb-8 flex justify-center">
              <img 
                src={LOGO_URL} 
                alt="Everscape Logo" 
                className="h-14 object-contain"
                onError={(e) => {
                   // Fallback SVG if image not found
                   e.currentTarget.src = "https://api.iconify.design/logos:everscale.svg";
                }}
              />
            </div>
            <h1 className="text-2xl font-bold text-slate-800 tracking-tight">GSS 안전관리</h1>
            <p className="text-slate-400 mt-2 text-sm font-medium">현장 맞춤형 스마트 안전 솔루션</p>
          </div>

          <div className="space-y-6">
            <div>
              <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-3">사용자 유형 선택</label>
              <div className="grid grid-cols-2 gap-3">
                <button 
                  onClick={() => setRole('Worker')}
                  className={`flex flex-col items-center justify-center gap-2 py-4 rounded-3xl font-bold text-sm transition-all border-2 ${role === 'Worker' ? 'border-[#0097b2] bg-[#f0f9fb] text-[#0097b2]' : 'border-slate-50 bg-slate-50 text-slate-400'}`}
                >
                  <UserIcon size={24} />
                  <span>근로자용</span>
                </button>
                <button 
                  onClick={() => setRole('Admin')}
                  className={`flex flex-col items-center justify-center gap-2 py-4 rounded-3xl font-bold text-sm transition-all border-2 ${role === 'Admin' ? 'border-[#0097b2] bg-[#f0f9fb] text-[#0097b2]' : 'border-slate-50 bg-slate-50 text-slate-400'}`}
                >
                  <ShieldCheck size={24} />
                  <span>관리자용</span>
                </button>
              </div>
            </div>

            <div className="space-y-4">
              <div className="group">
                <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">성함</label>
                <input 
                  type="text" 
                  placeholder="이름을 입력하세요" 
                  className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                />
              </div>
              <div>
                <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">비밀번호</label>
                <input 
                  type="password" 
                  placeholder="비밀번호를 입력하세요" 
                  className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all"
                />
              </div>
            </div>

            <button 
              onClick={() => handleLogin({ id: Math.random().toString(36).substr(2, 9), name: name || '사용자', role, email: 'user@gss.com' })}
              className="w-full bg-[#0097b2] text-white p-5 rounded-3xl font-bold shadow-xl shadow-[#0097b2]/20 active:scale-[0.98] transition-all mt-4 hover:bg-[#008199]"
            >
              {isReg ? '회원가입 완료' : '로그인'}
            </button>

            <button 
              onClick={() => setIsReg(!isReg)}
              className="w-full text-slate-400 text-xs font-semibold py-2"
            >
              {isReg ? '이미 계정이 있으신가요? 로그인' : '처음 방문하셨나요? 계정 만들기'}
            </button>
          </div>
        </div>
      </div>
    );
  };

  const SiteTabsScreen = () => {
    const currentSite = sites.find(s => s.id === activeSiteId);

    // Role-based filtering: Workers only see specific items
    const visibleCategories = currentSite?.categories.filter(cat => {
      if (currentUser?.role === 'Admin') return true;
      return cat.name === '현장 안전 점검' || cat.name === '위험발굴/작업중지';
    }) || [];

    return (
      <div className="flex flex-col h-screen bg-[#fafbfc]">
        {/* Header */}
        <div className="bg-white text-slate-800 px-5 pt-6 shrink-0 shadow-sm border-b border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <div className="flex items-center gap-3">
              <img 
                src={LOGO_URL} 
                alt="Logo" 
                className="h-7 object-contain"
                onError={(e) => e.currentTarget.style.display = 'none'}
              />
              <div className="h-4 w-px bg-slate-200" />
              <h1 className="text-lg font-extrabold text-[#0097b2] tracking-tight">GSS 안전관리</h1>
            </div>
            <div className="flex items-center gap-3">
               <div className="text-right hidden sm:block">
                  <p className="text-[10px] font-bold text-[#0097b2] leading-none uppercase tracking-tighter mb-0.5">
                    {currentUser?.role === 'Admin' ? 'SITE ADMIN' : 'WORKER'}
                  </p>
                  <p className="text-sm font-bold text-slate-800">{currentUser?.name}</p>
               </div>
               <button onClick={() => setCurrentUser(null)} className="p-2.5 bg-slate-50 hover:bg-red-50 hover:text-red-500 rounded-2xl transition-all text-slate-400">
                 <LogOut size={20}/>
               </button>
            </div>
          </div>

          {/* Tabs Row */}
          <div className="flex overflow-x-auto no-scrollbar gap-8 items-center">
            {sites.map(site => (
              <button
                key={site.id}
                onClick={() => setActiveSiteId(site.id)}
                className={`py-4 px-1 font-bold whitespace-nowrap transition-all relative text-sm tracking-tight ${activeSiteId === site.id ? 'text-[#0097b2]' : 'text-slate-400'}`}
              >
                {site.name}
                {activeSiteId === site.id && <div className="absolute bottom-0 left-0 right-0 h-1 bg-[#0097b2] rounded-t-full shadow-[0_-2px_6px_rgba(0,151,178,0.3)]" />}
              </button>
            ))}
            {currentUser?.role === 'Admin' && (
              <button 
                onClick={() => setView('ADD_SITE')}
                className="flex items-center gap-1.5 py-4 px-1 text-[#0097b2] font-bold whitespace-nowrap text-sm opacity-60 hover:opacity-100 transition-opacity"
              >
                <Plus size={16} /> 현장 추가
              </button>
            )}
          </div>
        </div>

        {/* Site Content (Menu) */}
        <div className="flex-1 overflow-y-auto p-5">
          {currentSite ? (
            <div className="max-w-2xl mx-auto space-y-5">
              <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100 mb-6">
                <div className="flex items-center gap-4 mb-5">
                  <div className="p-3.5 bg-[#f0f9fb] rounded-2xl">
                    <Building2 className="text-[#0097b2]" size={24} />
                  </div>
                  <div>
                    <h2 className="text-xl font-bold text-slate-900 leading-tight">{currentSite.name}</h2>
                    <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest mt-1">현장 총괄 정보</p>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100/50">
                    <p className="text-[10px] font-bold text-slate-400 mb-1.5 uppercase">현장소장</p>
                    <p className="text-[15px] font-bold text-slate-700">{currentSite.manager}</p>
                  </div>
                  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100/50">
                    <p className="text-[10px] font-bold text-slate-400 mb-1.5 uppercase">관리감독자</p>
                    <p className="text-[15px] font-bold text-slate-700">{currentSite.supervisor}</p>
                  </div>
                </div>
              </div>

              <div className="flex items-center justify-between px-2 mb-2">
                <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">관리 항목 리스트</h3>
                {currentUser?.role === 'Worker' && (
                  <span className="text-[10px] bg-[#f0f9fb] text-[#0097b2] font-bold px-2 py-0.5 rounded-full border border-[#0097b2]/10 uppercase">제한된 보기</span>
                )}
              </div>

              <div className="grid gap-3.5">
                {visibleCategories.map(cat => (
                  <button
                    key={cat.id}
                    onClick={() => { setActiveCategoryId(cat.id); setView('CATEGORY_DETAIL'); }}
                    className="w-full flex items-center justify-between p-6 bg-white rounded-[2rem] shadow-sm border border-slate-100 hover:border-[#0097b2]/40 hover:shadow-xl hover:shadow-slate-200/40 transition-all active:scale-[0.99] group"
                  >
                    <div className="flex items-center gap-5">
                      <div className="p-3 bg-slate-50 rounded-2xl group-hover:bg-[#f0f9fb] transition-colors">
                        <FileText size={22} className="text-slate-400 group-hover:text-[#0097b2]" />
                      </div>
                      <span className="font-bold text-slate-700 text-lg group-hover:text-[#0097b2] transition-colors tracking-tight">{cat.name}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      {cat.files.length > 0 && (
                        <span className="bg-[#0097b2] text-white text-[10px] font-extrabold px-2.5 py-1 rounded-full shadow-lg shadow-[#0097b2]/20">
                          {cat.files.length}
                        </span>
                      )}
                      <ChevronRight size={22} className="text-slate-300 group-hover:text-[#0097b2] group-hover:translate-x-1 transition-all" />
                    </div>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 py-20">
              <Building2 size={72} className="mb-6 opacity-10" />
              <p className="font-bold text-lg">등록된 현장이 없습니다.</p>
              {currentUser?.role === 'Admin' && (
                <button 
                  onClick={() => setView('ADD_SITE')}
                  className="mt-8 bg-[#0097b2] text-white px-10 py-5 rounded-[2rem] font-bold shadow-2xl shadow-[#0097b2]/30 active:scale-95 transition-all hover:bg-[#008199]"
                >
                  새 현장 등록하기
                </button>
              )}
            </div>
          )}
        </div>
      </div>
    );
  };

  const AddSiteScreen = () => {
    const [name, setName] = useState('');
    const [manager, setManager] = useState('');
    const [supervisor, setSupervisor] = useState('');

    return (
      <div className="h-screen bg-white flex flex-col">
        <div className="flex items-center p-5 border-b border-slate-100">
          <button onClick={() => setView('SITES')} className="p-2.5 -ml-2 text-slate-400 hover:text-[#0097b2] transition-colors rounded-2xl hover:bg-slate-50">
            <ArrowLeft size={24}/>
          </button>
          <h2 className="text-xl font-bold ml-2 text-slate-800 tracking-tight">현장 추가 등록</h2>
        </div>

        <div className="p-8 space-y-10 max-w-lg mx-auto w-full">
          <div className="space-y-6">
            <div className="group">
              <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">현장 프로젝트명</label>
              <input 
                className="w-full p-5 bg-slate-50 border border-slate-100 rounded-[1.5rem] focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all text-lg font-medium"
                placeholder="현장 이름을 입력하세요"
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
            </div>
            <div>
              <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">총괄 현장소장</label>
              <input 
                className="w-full p-5 bg-slate-50 border border-slate-100 rounded-[1.5rem] focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all font-medium"
                placeholder="소장님 성함을 입력하세요"
                value={manager}
                onChange={(e) => setManager(e.target.value)}
              />
            </div>
            <div>
              <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">안전 관리감독자</label>
              <input 
                className="w-full p-5 bg-slate-50 border border-slate-100 rounded-[1.5rem] focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all font-medium"
                placeholder="관리감독자 성함을 입력하세요"
                value={supervisor}
                onChange={(e) => setSupervisor(e.target.value)}
              />
            </div>
          </div>

          <button 
            onClick={() => name && addSite(name, manager, supervisor)}
            className="w-full bg-[#0097b2] text-white p-5 rounded-[2rem] font-bold shadow-2xl shadow-[#0097b2]/20 active:scale-95 transition-all hover:bg-[#008199] text-lg"
          >
            현장 정보 저장
          </button>
        </div>
      </div>
    );
  };

  const CategoryDetailScreen = () => {
    const site = sites.find(s => s.id === activeSiteId);
    const category = site?.categories.find(c => c.id === activeCategoryId);

    if (!category) return null;

    return (
      <div className="h-screen bg-slate-50 flex flex-col">
        {/* Header */}
        <div className="bg-white border-b border-slate-200 p-5 flex items-center justify-between shrink-0 sticky top-0 z-10">
          <div className="flex items-center min-w-0">
            <button onClick={() => setView('SITES')} className="p-2.5 -ml-2 text-slate-400 hover:text-[#0097b2] transition-colors rounded-2xl hover:bg-slate-50">
              <ArrowLeft size={24}/>
            </button>
            <div className="ml-3 min-w-0">
              <h2 className="text-xl font-bold text-slate-900 leading-none truncate tracking-tight">{category.name}</h2>
              <p className="text-[10px] font-bold text-[#0097b2] mt-1.5 uppercase tracking-widest truncate">{site?.name}</p>
            </div>
          </div>
          <div className="flex gap-2">
             <label className="bg-[#0097b2] text-white p-3 rounded-[1.25rem] shadow-xl shadow-[#0097b2]/20 cursor-pointer active:scale-90 transition-all hover:bg-[#008199]">
                <FileUp size={24} />
                <input type="file" multiple className="hidden" onChange={handleFileUpload} />
             </label>
          </div>
        </div>

        {/* File List */}
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
