            </div>
          ) : (
            <div className="max-w-3xl mx-auto space-y-4">
              <div className="flex items-center justify-between px-3 mb-2">
                <span className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">문서 리스트 ({category.files.length})</span>
              </div>
              {category.files.map(file => (
                <div key={file.id} className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-100 flex items-center justify-between group hover:border-[#0097b2]/40 transition-all">
                  <div className="flex items-center gap-4 overflow-hidden">
                    <div className="shrink-0 w-14 h-14 flex items-center justify-center bg-slate-50 rounded-[1.25rem] group-hover:bg-[#f0f9fb] transition-colors overflow-hidden border border-slate-50">
                      {file.type.includes('image') ? (
                        <img src={file.url} className="w-full h-full object-cover" alt="Preview" />
                      ) : (
                        file.type.includes('sheet') ? 
                        <FileSpreadsheet size={24} className="text-green-600" /> :
                        <FileText size={24} className="text-slate-400" />
                      )}
                    </div>
                    <div className="overflow-hidden">
                      <p className="text-[15px] font-bold text-slate-800 truncate leading-tight mb-2 tracking-tight">{file.name}</p>
                      <div className="flex flex-wrap items-center gap-x-2 gap-y-1">
                        <span className="text-[9px] font-extrabold text-white bg-[#0097b2] px-2 py-0.5 rounded-full uppercase tracking-tighter">
                          {file.uploaderRole === 'Admin' ? '관리자' : '근로자'}
                        </span>
                        <span className="text-[11px] font-bold text-slate-600">{file.uploadedBy}</span>
                        <span className="text-slate-200 text-xs">•</span>
                        <span className="text-[11px] text-slate-400 font-medium">{file.uploadedAt}</span>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-2 shrink-0 ml-4">
                    <a 
                      href={file.url} 
                      download={file.name}
                      className="p-3 text-[#0097b2] hover:bg-[#f0f9fb] rounded-2xl transition-all"
                      title="다운로드"
                    >
                      <Download size={20} />
                    </a>
                    {(currentUser?.role === 'Admin' || currentUser?.name === file.uploadedBy) && (
                      <button 
                        onClick={() => deleteFile(file.id)} 
                        className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-2xl transition-all"
                        title="삭제"
                      >
                        <Trash2 size={20} />
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Quick Upload Hint */}
        <div className="px-8 pb-10 pt-5 shrink-0 bg-white/60 backdrop-blur-xl border-t border-slate-100">
           <label className="w-full bg-[#f8fafc] border-2 border-dashed border-slate-200 p-6 rounded-[2rem] flex items-center justify-center gap-3 text-slate-400 cursor-pointer hover:border-[#0097b2] hover:text-[#0097b2] hover:bg-[#f0f9fb] transition-all group">
              <FileUp size={22} className="group-hover:scale-110 transition-transform" />
              <span className="text-[15px] font-bold">새로운 파일 추가 업로드</span>
              <input type="file" multiple className="hidden" onChange={handleFileUpload} />
           </label>
        </div>
      </div>
    );
  };

  // --- Router ---
  if (view === 'AUTH') return <AuthScreen />;
  if (view === 'ADD_SITE') return <AddSiteScreen />;
  if (view === 'CATEGORY_DETAIL') return <CategoryDetailScreen />;

  return <SiteTabsScreen />;
}

import React, { useState } from 'react';
import { User, UserRole, ConstructionSite, SiteCategory, UploadedFile } from './types';
import { INITIAL_SITES, DEFAULT_CATEGORIES } from './constants';
import { 
  Plus, 
  ChevronRight, 
  FileUp, 
  LogOut, 
  Building2, 
  X, 
  FileText, 
  Image as ImageIcon, 
  FileSpreadsheet,
  ArrowLeft,
  Download,
  Trash2,
  ShieldCheck,
  User as UserIcon,
  Share2,
  Copy,
  Check
} from 'lucide-react';

// --- Types of Views ---
type ViewState = 'AUTH' | 'SITES' | 'ADD_SITE' | 'MENU' | 'CATEGORY_DETAIL';

// Everscape Teal color: #0097b2
const PRIMARY_TEAL = '#0097b2';
const LOGO_URL = 'https://raw.githubusercontent.com/t-park/everscape-logo/main/everscape_logo.png';

export default function App() {
  // --- State ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('AUTH');
  const [sites, setSites] = useState<ConstructionSite[]>(INITIAL_SITES);
  const [activeSiteId, setActiveSiteId] = useState<string | null>(null);
  const [activeCategoryId, setActiveCategoryId] = useState<string | null>(null);

  // --- Auth Handlers ---
  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setView('SITES');
    if (sites.length > 0) setActiveSiteId(sites[0].id);
  };

  // --- Site Handlers ---
  const addSite = (name: string, manager: string, supervisor: string) => {
    const newSite: ConstructionSite = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      manager,
      supervisor,
      categories: DEFAULT_CATEGORIES.map(catName => ({
        id: Math.random().toString(36).substr(2, 9),
        name: catName,
        files: []
      }))
    };
    setSites([...sites, newSite]);
    setActiveSiteId(newSite.id);
    setView('SITES');
  };

  // --- File Handlers ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || !activeSiteId || !activeCategoryId || !currentUser) return;

    const newFiles: UploadedFile[] = Array.from(files).map((file: File) => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      type: file.type,
      size: file.size,
      uploadedAt: new Date().toLocaleString('ko-KR', { 
        year: 'numeric', month: '2-digit', day: '2-digit', 
        hour: '2-digit', minute: '2-digit' 
      }),
      uploadedBy: currentUser.name,
      uploaderRole: currentUser.role,
      url: URL.createObjectURL(file)
    }));

    setSites(prev => prev.map(site => {
      if (site.id !== activeSiteId) return site;
      return {
        ...site,
        categories: site.categories.map(cat => {
          if (cat.id !== activeCategoryId) return cat;
          return { ...cat, files: [...cat.files, ...newFiles] };
        })
      };
    }));
  };

  const deleteFile = (fileId: string) => {
    setSites(prev => prev.map(site => {
      if (site.id !== activeSiteId) return site;
      return {
        ...site,
        categories: site.categories.map(cat => {
          if (cat.id !== activeCategoryId) return cat;
          return { ...cat, files: cat.files.filter(f => f.id !== fileId) };
        })
      };
    }));
  };

  // --- Sub-Components ---

  const AuthScreen = () => {
    const [isReg, setIsReg] = useState(false);
    const [role, setRole] = useState<UserRole>('Worker');
    const [name, setName] = useState('');
    const [shared, setShared] = useState(false);

    const handleShare = async () => {
      const shareData = {
        title: 'GSS 안전관리 - 에버스케이프',
        text: '건설 현장 맞춤형 스마트 안전 솔루션, GSS 안전관리 앱을 확인해보세요.',
        url: window.location.href,
      };

      try {
        if (navigator.share) {
          await navigator.share(shareData);
        } else {
          await navigator.clipboard.writeText(window.location.href);
          setShared(true);
          setTimeout(() => setShared(false), 2000);
        }
      } catch (err) {
        console.error('Error sharing:', err);
      }
    };

    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
        <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 shadow-2xl shadow-slate-200/60 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-full mb-8 flex justify-center">
              <img 
                src={LOGO_URL} 
                alt="Everscape Logo" 
                className="h-14 object-contain"
                onError={(e) => {
                   e.currentTarget.src = "https://api.iconify.design/logos:everscale.svg";
                }}
              />
            </div>
            <h1 className="text-2xl font-bold text-slate-800 tracking-tight">GSS 안전관리</h1>
            <p className="text-slate-400 mt-2 text-sm font-medium">현장 맞춤형 스마트 안전 솔루션</p>
          </div>

          <div className="space-y-6">
            <div>
              <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-3">사용자 유형 선택</label>
              <div className="grid grid-cols-2 gap-3">
                <button 
                  onClick={() => setRole('Worker')}
                  className={`flex flex-col items-center justify-center gap-2 py-4 rounded-3xl font-bold text-sm transition-all border-2 ${role === 'Worker' ? 'border-[#0097b2] bg-[#f0f9fb] text-[#0097b2]' : 'border-slate-50 bg-slate-50 text-slate-400'}`}
                >
                  <UserIcon size={24} />
                  <span>근로자용</span>
                </button>
                <button 
                  onClick={() => setRole('Admin')}
                  className={`flex flex-col items-center justify-center gap-2 py-4 rounded-3xl font-bold text-sm transition-all border-2 ${role === 'Admin' ? 'border-[#0097b2] bg-[#f0f9fb] text-[#0097b2]' : 'border-slate-50 bg-slate-50 text-slate-400'}`}
                >
                  <ShieldCheck size={24} />
                  <span>관리자용</span>
                </button>
              </div>
            </div>

            <div className="space-y-4">
              <div className="group">
                <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">성함</label>
                <input 
                  type="text" 
                  placeholder="이름을 입력하세요" 
                  className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                />
              </div>
              <div>
                <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">비밀번호</label>
                <input 
                  type="password" 
                  placeholder="비밀번호를 입력하세요" 
                  className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all"
                />
              </div>
            </div>

            <button 
              onClick={() => handleLogin({ id: Math.random().toString(36).substr(2, 9), name: name || '사용자', role, email: 'user@gss.com' })}
              className="w-full bg-[#0097b2] text-white p-5 rounded-3xl font-bold shadow-xl shadow-[#0097b2]/20 active:scale-[0.98] transition-all mt-4 hover:bg-[#008199]"
            >
              {isReg ? '회원가입 완료' : '로그인'}
            </button>

            <div className="pt-2">
              <button 
                onClick={() => setIsReg(!isReg)}
                className="w-full text-slate-400 text-xs font-semibold py-2"
              >
                {isReg ? '이미 계정이 있으신가요? 로그인' : '처음 방문하셨나요? 계정 만들기'}
              </button>
            </div>

            {/* Share Section */}
            <div className="pt-4 border-t border-slate-100">
              <p className="text-center text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-3">어플 공유하기</p>
              <button 
                onClick={handleShare}
                className="w-full flex items-center justify-center gap-2 py-3 rounded-2xl border-2 border-slate-100 text-slate-600 font-bold text-sm hover:bg-slate-50 transition-all active:scale-95"
              >
                {shared ? <Check size={18} className="text-[#0097b2]" /> : <Share2 size={18} />}
                {shared ? '링크가 복사되었습니다' : '동료에게 어플 공유하기'}
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  };

  const SiteTabsScreen = () => {
    const currentSite = sites.find(s => s.id === activeSiteId);

    // Role-based filtering: Workers only see specific items
    const visibleCategories = currentSite?.categories.filter(cat => {
      if (currentUser?.role === 'Admin') return true;
      return cat.name === '현장 안전 점검' || cat.name === '위험발굴/작업중지';
    }) || [];

    return (
      <div className="flex flex-col h-screen bg-[#fafbfc]">
        {/* Header */}
        <div className="bg-white text-slate-800 px-5 pt-6 shrink-0 shadow-sm border-b border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <div className="flex items-center gap-3">
              <img 
                src={LOGO_URL} 
                alt="Logo" 
                className="h-7 object-contain"
                onError={(e) => e.currentTarget.style.display = 'none'}
              />
              <div className="h-4 w-px bg-slate-200" />
              <h1 className="text-lg font-extrabold text-[#0097b2] tracking-tight">GSS 안전관리</h1>
            </div>
            <div className="flex items-center gap-3">
               <div className="text-right hidden sm:block">
                  <p className="text-[10px] font-bold text-[#0097b2] leading-none uppercase tracking-tighter mb-0.5">
                    {currentUser?.role === 'Admin' ? 'SITE ADMIN' : 'WORKER'}
                  </p>
                  <p className="text-sm font-bold text-slate-800">{currentUser?.name}</p>
               </div>
               <button onClick={() => setCurrentUser(null)} className="p-2.5 bg-slate-50 hover:bg-red-50 hover:text-red-500 rounded-2xl transition-all text-slate-400">
                 <LogOut size={20}/>
               </button>
            </div>
          </div>

          {/* Tabs Row */}
          <div className="flex overflow-x-auto no-scrollbar gap-8 items-center">
            {sites.map(site => (
              <button
                key={site.id}
                onClick={() => setActiveSiteId(site.id)}
                className={`py-4 px-1 font-bold whitespace-nowrap transition-all relative text-sm tracking-tight ${activeSiteId === site.id ? 'text-[#0097b2]' : 'text-slate-400'}`}
              >
                {site.name}
                {activeSiteId === site.id && <div className="absolute bottom-0 left-0 right-0 h-1 bg-[#0097b2] rounded-t-full shadow-[0_-2px_6px_rgba(0,151,178,0.3)]" />}
              </button>
            ))}
            {currentUser?.role === 'Admin' && (
              <button 
                onClick={() => setView('ADD_SITE')}
                className="flex items-center gap-1.5 py-4 px-1 text-[#0097b2] font-bold whitespace-nowrap text-sm opacity-60 hover:opacity-100 transition-opacity"
              >
                <Plus size={16} /> 현장 추가
              </button>
            )}
          </div>
        </div>

        {/* Site Content (Menu) */}
        <div className="flex-1 overflow-y-auto p-5">
          {currentSite ? (
            <div className="max-w-2xl mx-auto space-y-5">
              <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100 mb-6">
                <div className="flex items-center gap-4 mb-5">
                  <div className="p-3.5 bg-[#f0f9fb] rounded-2xl">
                    <Building2 className="text-[#0097b2]" size={24} />
                  </div>
                  <div>
                    <h2 className="text-xl font-bold text-slate-900 leading-tight">{currentSite.name}</h2>
                    <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest mt-1">현장 총괄 정보</p>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100/50">
                    <p className="text-[10px] font-bold text-slate-400 mb-1.5 uppercase">현장소장</p>
                    <p className="text-[15px] font-bold text-slate-700">{currentSite.manager}</p>
                  </div>
                  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100/50">
                    <p className="text-[10px] font-bold text-slate-400 mb-1.5 uppercase">안전 관리감독자</p>
                    <p className="text-[15px] font-bold text-slate-700">{currentSite.supervisor}</p>
                  </div>
                </div>
              </div>

              <div className="flex items-center justify-between px-2 mb-2">
                <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">관리 항목 리스트</h3>
                {currentUser?.role === 'Worker' && (
                  <span className="text-[10px] bg-[#f0f9fb] text-[#0097b2] font-bold px-2 py-0.5 rounded-full border border-[#0097b2]/10 uppercase">제한된 보기</span>
                )}
              </div>

              <div className="grid gap-3.5">
                {visibleCategories.map(cat => (
                  <button
                    key={cat.id}
                    onClick={() => { setActiveCategoryId(cat.id); setView('CATEGORY_DETAIL'); }}
                    className="w-full flex items-center justify-between p-6 bg-white rounded-[2rem] shadow-sm border border-slate-100 hover:border-[#0097b2]/40 hover:shadow-xl hover:shadow-slate-200/40 transition-all active:scale-[0.99] group"
                  >
                    <div className="flex items-center gap-5">
                      <div className="p-3 bg-slate-50 rounded-2xl group-hover:bg-[#f0f9fb] transition-colors">
                        <FileText size={22} className="text-slate-400 group-hover:text-[#0097b2]" />
                      </div>
                      <span className="font-bold text-slate-700 text-lg group-hover:text-[#0097b2] transition-colors tracking-tight">{cat.name}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      {cat.files.length > 0 && (
                        <span className="bg-[#0097b2] text-white text-[10px] font-extrabold px-2.5 py-1 rounded-full shadow-lg shadow-[#0097b2]/20">
                          {cat.files.length}
                        </span>
                      )}
                      <ChevronRight size={22} className="text-slate-300 group-hover:text-[#0097b2] group-hover:translate-x-1 transition-all" />
                    </div>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 py-20">
              <Building2 size={72} className="mb-6 opacity-10" />
              <p className="font-bold text-lg">등록된 현장이 없습니다.</p>
              {currentUser?.role === 'Admin' && (
                <button 
                  onClick={() => setView('ADD_SITE')}
                  className="mt-8 bg-[#0097b2] text-white px-10 py-5 rounded-[2rem] font-bold shadow-2xl shadow-[#0097b2]/30 active:scale-95 transition-all hover:bg-[#008199]"
                >
                  새 현장 등록하기
                </button>
              )}
            </div>
          )}
        </div>
      </div>
    );
  };

  const AddSiteScreen = () => {
    const [name, setName] = useState('');
    const [manager, setManager] = useState('');
    const [supervisor, setSupervisor] = useState('');

    return (
      <div className="h-screen bg-white flex flex-col">
        <div className="flex items-center p-5 border-b border-slate-100">
          <button onClick={() => setView('SITES')} className="p-2.5 -ml-2 text-slate-400 hover:text-[#0097b2] transition-colors rounded-2xl hover:bg-slate-50">
            <ArrowLeft size={24}/>
          </button>
          <h2 className="text-xl font-bold ml-2 text-slate-800 tracking-tight">현장 추가 등록</h2>
        </div>

        <div className="p-8 space-y-10 max-w-lg mx-auto w-full">
          <div className="space-y-6">
            <div className="group">
              <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">현장 프로젝트명</label>
              <input 
                className="w-full p-5 bg-slate-50 border border-slate-100 rounded-[1.5rem] focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all text-lg font-medium"
                placeholder="현장 이름을 입력하세요"
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
            </div>
            <div>
              <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">총괄 현장소장</label>
              <input 
                className="w-full p-5 bg-slate-50 border border-slate-100 rounded-[1.5rem] focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all font-medium"
                placeholder="소장님 성함을 입력하세요"
                value={manager}
                onChange={(e) => setManager(e.target.value)}
              />
            </div>
            <div>
              <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">안전 관리감독자</label>
              <input 
                className="w-full p-5 bg-slate-50 border border-slate-100 rounded-[1.5rem] focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all font-medium"
                placeholder="관리감독자 성함을 입력하세요"
                value={supervisor}
                onChange={(e) => setSupervisor(e.target.value)}
              />
            </div>
          </div>

          <button 
            onClick={() => name && addSite(name, manager, supervisor)}
            className="w-full bg-[#0097b2] text-white p-5 rounded-[2rem] font-bold shadow-2xl shadow-[#0097b2]/20 active:scale-95 transition-all hover:bg-[#008199] text-lg"
          >
            현장 정보 저장
          </button>
        </div>
      </div>
    );
  };

  const CategoryDetailScreen = () => {
    const site = sites.find(s => s.id === activeSiteId);
    const category = site?.categories.find(c => c.id === activeCategoryId);

    if (!category) return null;

    return (
      <div className="h-screen bg-slate-50 flex flex-col">
        {/* Header */}
        <div className="bg-white border-b border-slate-200 p-5 flex items-center justify-between shrink-0 sticky top-0 z-10">
          <div className="flex items-center min-w-0">
            <button onClick={() => setView('SITES')} className="p-2.5 -ml-2 text-slate-400 hover:text-[#0097b2] transition-colors rounded-2xl hover:bg-slate-50">
              <ArrowLeft size={24}/>
            </button>
            <div className="ml-3 min-w-0">
              <h2 className="text-xl font-bold text-slate-900 leading-none truncate tracking-tight">{category.name}</h2>
              <p className="text-[10px] font-bold text-[#0097b2] mt-1.5 uppercase tracking-widest truncate">{site?.name}</p>
            </div>
          </div>
          <div className="flex gap-2">
             <label className="bg-[#0097b2] text-white p-3 rounded-[1.25rem] shadow-xl shadow-[#0097b2]/20 cursor-pointer active:scale-90 transition-all hover:bg-[#008199]">
                <FileUp size={24} />
                <input type="file" multiple className="hidden" onChange={handleFileUpload} />
             </label>
          </div>
        </div>

        {/* File List */}
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          {category.files.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300 py-20">
              <div className="bg-white p-10 rounded-[3rem] shadow-sm mb-6 border border-slate-50">
                <FileUp size={64} className="text-[#0097b2] opacity-20" />
              </div>
              <p className="font-bold text-slate-400 text-lg">업로드된 파일이 없습니다</p>
              <p className="text-xs mt-2 font-semibold text-slate-400 bg-slate-200/50 px-4 py-1.5 rounded-full uppercase tracking-tighter">
                우측 상단 + 버튼을 터치하여 추가하세요
              </p>
            </div>
          ) : (
            <div className="max-w-3xl mx-auto space-y-4">
              <div className="flex items-center justify-between px-3 mb-2">
                <span className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">문서 리스트 ({category.files.length})</span>
              </div>
              {category.files.map(file => (
                <div key={file.id} className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-100 flex items-center justify-between group hover:border-[#0097b2]/40 transition-all">
                  <div className="flex items-center gap-4 overflow-hidden">
                    <div className="shrink-0 w-14 h-14 flex items-center justify-center bg-slate-50 rounded-[1.25rem] group-hover:bg-[#f0f9fb] transition-colors overflow-hidden border border-slate-50">
                      {file.type.includes('image') ? (
                        <img src={file.url} className="w-full h-full object-cover" alt="Preview" />
                      ) : (
                        file.type.includes('sheet') ? 
                        <FileSpreadsheet size={24} className="text-green-600" /> :
                        <FileText size={24} className="text-slate-400" />
                      )}
                    </div>
                    <div className="overflow-hidden">
                      <p className="text-[15px] font-bold text-slate-800 truncate leading-tight mb-2 tracking-tight">{file.name}</p>
                      <div className="flex flex-wrap items-center gap-x-2 gap-y-1">
                        <span className="text-[9px] font-extrabold text-white bg-[#0097b2] px-2 py-0.5 rounded-full uppercase tracking-tighter">
                          {file.uploaderRole === 'Admin' ? '관리자' : '근로자'}
                        </span>
                        <span className="text-[11px] font-bold text-slate-600">{file.uploadedBy}</span>
                        <span className="text-slate-200 text-xs">•</span>
                        <span className="text-[11px] text-slate-400 font-medium">{file.uploadedAt}</span>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-2 shrink-0 ml-4">
                    <a 
                      href={file.url} 
                      download={file.name}
                      className="p-3 text-[#0097b2] hover:bg-[#f0f9fb] rounded-2xl transition-all"
                      title="다운로드"
                    >
                      <Download size={20} />
                    </a>
                    {(currentUser?.role === 'Admin' || currentUser?.name === file.uploadedBy) && (
                      <button 
                        onClick={() => deleteFile(file.id)} 
                        className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-2xl transition-all"
                        title="삭제"
                      >
                        <Trash2 size={20} />
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Quick Upload Hint */}
        <div className="px-8 pb-10 pt-5 shrink-0 bg-white/60 backdrop-blur-xl border-t border-slate-100">
           <label className="w-full bg-[#f8fafc] border-2 border-dashed border-slate-200 p-6 rounded-[2rem] flex items-center justify-center gap-3 text-slate-400 cursor-pointer hover:border-[#0097b2] hover:text-[#0097b2] hover:bg-[#f0f9fb] transition-all group">
              <FileUp size={22} className="group-hover:scale-110 transition-transform" />
              <span className="text-[15px] font-bold">새로운 파일 추가 업로드</span>
              <input type="file" multiple className="hidden" onChange={handleFileUpload} />
           </label>
        </div>
      </div>
    );
  };

  // --- Router ---
  if (view === 'AUTH') return <AuthScreen />;
  if (view === 'ADD_SITE') return <AddSiteScreen />;
  if (view === 'CATEGORY_DETAIL') return <CategoryDetailScreen />;

  return <SiteTabsScreen />;
}

export type UserRole = 'Worker' | 'Admin';

export interface User {
  id: string;
  name: string;
  role: UserRole;
  email: string;
}

export interface UploadedFile {
  id: string;
  name: string;
  type: string;
  size: number;
  uploadedAt: string;
  uploadedBy: string;
  uploaderRole: UserRole;
  url: string;
}

export interface SafetyReport {
  id: string;
  type: '위험발굴' | '작업중지';
  date: string;
  issue: string;
  action: string;
  imageUrl?: string;
  uploadedAt: string;
  uploadedBy: string;
  uploaderRole: UserRole;
}

export interface SiteCategory {
  id: string;
  name: string;
  files: UploadedFile[];
  reports?: SafetyReport[];
}

export interface ConstructionSite {
  id: string;
  name: string;
  manager: string;
  supervisor: string;
  categories: SiteCategory[];
}

import React, { useState } from 'react';
import { User, UserRole, ConstructionSite, SiteCategory, UploadedFile, SafetyReport } from './types';
import { INITIAL_SITES, DEFAULT_CATEGORIES } from './constants';
import { 
  Plus, 
  ChevronRight, 
  FileUp, 
  LogOut, 
  Building2, 
  X, 
  FileText, 
  Image as ImageIcon, 
  FileSpreadsheet,
  ArrowLeft,
  Download,
  Trash2,
  ShieldCheck,
  User as UserIcon,
  Share2,
  Check,
  ClipboardList,
  Calendar,
  AlertTriangle,
  Zap,
  Camera
} from 'lucide-react';

// --- Types of Views ---
type ViewState = 'AUTH' | 'SITES' | 'ADD_SITE' | 'MENU' | 'CATEGORY_DETAIL' | 'REPORT_FORM';

const PRIMARY_TEAL = '#0097b2';
const LOGO_URL = 'https://raw.githubusercontent.com/t-park/everscape-logo/main/everscape_logo.png';

export default function App() {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('AUTH');
  const [sites, setSites] = useState<ConstructionSite[]>(INITIAL_SITES);
  const [activeSiteId, setActiveSiteId] = useState<string | null>(null);
  const [activeCategoryId, setActiveCategoryId] = useState<string | null>(null);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setView('SITES');
    if (sites.length > 0) setActiveSiteId(sites[0].id);
  };

  const addSite = (name: string, manager: string, supervisor: string) => {
    const newSite: ConstructionSite = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      manager,
      supervisor,
      categories: DEFAULT_CATEGORIES.map(catName => ({
        id: Math.random().toString(36).substr(2, 9),
        name: catName,
        files: [],
        reports: []
      }))
    };
    setSites([...sites, newSite]);
    setActiveSiteId(newSite.id);
    setView('SITES');
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || !activeSiteId || !activeCategoryId || !currentUser) return;

    const newFiles: UploadedFile[] = Array.from(files).map((file: File) => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      type: file.type,
      size: file.size,
      uploadedAt: new Date().toLocaleString('ko-KR'),
      uploadedBy: currentUser.name,
      uploaderRole: currentUser.role,
      url: URL.createObjectURL(file)
    }));

    updateSitesData(activeSiteId, activeCategoryId, (cat) => ({
      ...cat,
      files: [...cat.files, ...newFiles]
    }));
  };

  const handleReportSubmit = (report: Omit<SafetyReport, 'id' | 'uploadedAt' | 'uploadedBy' | 'uploaderRole'>) => {
    if (!activeSiteId || !activeCategoryId || !currentUser) return;

    const newReport: SafetyReport = {
      ...report,
      id: Math.random().toString(36).substr(2, 9),
      uploadedAt: new Date().toLocaleString('ko-KR'),
      uploadedBy: currentUser.name,
      uploaderRole: currentUser.role
    };

    updateSitesData(activeSiteId, activeCategoryId, (cat) => ({
      ...cat,
      reports: [...(cat.reports || []), newReport]
    }));
    setView('CATEGORY_DETAIL');
  };

  const updateSitesData = (siteId: string, catId: string, updateFn: (cat: SiteCategory) => SiteCategory) => {
    setSites(prev => prev.map(site => {
      if (site.id !== siteId) return site;
      return {
        ...site,
        categories: site.categories.map(cat => {
          if (cat.id !== catId) return cat;
          return updateFn(cat);
        })
      };
    }));
  };

  const deleteItem = (id: string, type: 'file' | 'report') => {
    if (!activeSiteId || !activeCategoryId) return;
    updateSitesData(activeSiteId, activeCategoryId, (cat) => ({
      ...cat,
      files: type === 'file' ? cat.files.filter(f => f.id !== id) : cat.files,
      reports: type === 'report' ? (cat.reports || []).filter(r => r.id !== id) : (cat.reports || [])
    }));
  };

  // --- Sub-Components ---

  const AuthScreen = () => {
    const [isReg, setIsReg] = useState(false);
    const [role, setRole] = useState<UserRole>('Worker');
    const [name, setName] = useState('');
    const [shared, setShared] = useState(false);

    const handleShare = async () => {
      const shareData = {
        title: 'GSS 안전관리 - 에버스케이프',
        text: '건설 현장 맞춤형 스마트 안전 솔루션, GSS 안전관리 앱을 확인해보세요.',
        url: window.location.href,
      };
      try {
        if (navigator.share) await navigator.share(shareData);
        else {
          await navigator.clipboard.writeText(window.location.href);
          setShared(true);
          setTimeout(() => setShared(false), 2000);
        }
      } catch (err) { console.error('Error sharing:', err); }
    };

    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
        <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 shadow-2xl shadow-slate-200/60 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-full mb-8 flex justify-center">
              <img src={LOGO_URL} alt="Everscape Logo" className="h-14 object-contain" onError={(e) => { e.currentTarget.src = "https://api.iconify.design/logos:everscale.svg"; }} />
            </div>
            <h1 className="text-2xl font-bold text-slate-800 tracking-tight">GSS 안전관리</h1>
            <p className="text-slate-400 mt-2 text-sm font-medium">현장 맞춤형 스마트 안전 솔루션</p>
          </div>
          <div className="space-y-6">
            <div>
              <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-3">사용자 유형 선택</label>
              <div className="grid grid-cols-2 gap-3">
                <button onClick={() => setRole('Worker')} className={`flex flex-col items-center justify-center gap-2 py-4 rounded-3xl font-bold text-sm transition-all border-2 ${role === 'Worker' ? 'border-[#0097b2] bg-[#f0f9fb] text-[#0097b2]' : 'border-slate-50 bg-slate-50 text-slate-400'}`}>
                  <UserIcon size={24} />
                  <span>근로자용</span>
                </button>
                <button onClick={() => setRole('Admin')} className={`flex flex-col items-center justify-center gap-2 py-4 rounded-3xl font-bold text-sm transition-all border-2 ${role === 'Admin' ? 'border-[#0097b2] bg-[#f0f9fb] text-[#0097b2]' : 'border-slate-50 bg-slate-50 text-slate-400'}`}>
                  <ShieldCheck size={24} />
                  <span>관리자용</span>
                </button>
              </div>
            </div>
            <div className="space-y-4">
              <div className="group">
                <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">성함</label>
                <input type="text" placeholder="이름을 입력하세요" className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all" value={name} onChange={(e) => setName(e.target.value)} />
              </div>
              <div>
                <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">비밀번호</label>
                <input type="password" placeholder="비밀번호를 입력하세요" className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all" />
              </div>
            </div>
            <button onClick={() => handleLogin({ id: Math.random().toString(36).substr(2, 9), name: name || '사용자', role, email: 'user@gss.com' })} className="w-full bg-[#0097b2] text-white p-5 rounded-3xl font-bold shadow-xl shadow-[#0097b2]/20 active:scale-[0.98] transition-all mt-4 hover:bg-[#008199]">
              {isReg ? '회원가입 완료' : '로그인'}
            </button>
            <div className="pt-2 text-center">
              <button onClick={() => setIsReg(!isReg)} className="text-slate-400 text-xs font-semibold py-2">
                {isReg ? '이미 계정이 있으신가요? 로그인' : '처음 방문하셨나요? 계정 만들기'}
              </button>
            </div>
            <div className="pt-4 border-t border-slate-100">
              <p className="text-center text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-3">어플 공유하기</p>
              <button onClick={handleShare} className="w-full flex items-center justify-center gap-2 py-3 rounded-2xl border-2 border-slate-100 text-slate-600 font-bold text-sm hover:bg-slate-50 transition-all active:scale-95">
                {shared ? <Check size={18} className="text-[#0097b2]" /> : <Share2 size={18} />}
                {shared ? '링크가 복사되었습니다' : '동료에게 어플 공유하기'}
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  };

  const SiteTabsScreen = () => {
    const currentSite = sites.find(s => s.id === activeSiteId);
    const visibleCategories = currentSite?.categories.filter(cat => {
      if (currentUser?.role === 'Admin') return true;
      return cat.name === '현장 안전 점검' || cat.name === '위험발굴/작업중지';
    }) || [];

    return (
      <div className="flex flex-col h-screen bg-[#fafbfc]">
        <div className="bg-white text-slate-800 px-5 pt-6 shrink-0 shadow-sm border-b border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <div className="flex items-center gap-3">
              <img src={LOGO_URL} alt="Logo" className="h-7 object-contain" onError={(e) => e.currentTarget.style.display = 'none'} />
              <div className="h-4 w-px bg-slate-200" />
              <h1 className="text-lg font-extrabold text-[#0097b2] tracking-tight">GSS 안전관리</h1>
            </div>
            <div className="flex items-center gap-3">
               <div className="text-right hidden sm:block">
                  <p className="text-[10px] font-bold text-[#0097b2] leading-none uppercase tracking-tighter mb-0.5">{currentUser?.role === 'Admin' ? 'SITE ADMIN' : 'WORKER'}</p>
                  <p className="text-sm font-bold text-slate-800">{currentUser?.name}</p>
               </div>
               <button onClick={() => setCurrentUser(null)} className="p-2.5 bg-slate-50 hover:bg-red-50 hover:text-red-500 rounded-2xl transition-all text-slate-400">
                 <LogOut size={20}/>
               </button>
            </div>
          </div>
          <div className="flex overflow-x-auto no-scrollbar gap-8 items-center">
            {sites.map(site => (
              <button key={site.id} onClick={() => setActiveSiteId(site.id)} className={`py-4 px-1 font-bold whitespace-nowrap transition-all relative text-sm tracking-tight ${activeSiteId === site.id ? 'text-[#0097b2]' : 'text-slate-400'}`}>
                {site.name}
                {activeSiteId === site.id && <div className="absolute bottom-0 left-0 right-0 h-1 bg-[#0097b2] rounded-t-full shadow-[0_-2px_6px_rgba(0,151,178,0.3)]" />}
              </button>
            ))}
            {currentUser?.role === 'Admin' && (
              <button onClick={() => setView('ADD_SITE')} className="flex items-center gap-1.5 py-4 px-1 text-[#0097b2] font-bold whitespace-nowrap text-sm opacity-60 hover:opacity-100 transition-opacity">
                <Plus size={16} /> 현장 추가
              </button>
            )}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-5">
          {currentSite ? (
            <div className="max-w-2xl mx-auto space-y-5">
              <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100 mb-6">
                <div className="flex items-center gap-4 mb-5">
                  <div className="p-3.5 bg-[#f0f9fb] rounded-2xl">
                    <Building2 className="text-[#0097b2]" size={24} />
                  </div>
                  <div>
                    <h2 className="text-xl font-bold text-slate-900 leading-tight">{currentSite.name}</h2>
                    <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest mt-1">현장 총괄 정보</p>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100/50">
                    <p className="text-[10px] font-bold text-slate-400 mb-1.5 uppercase">현장소장</p>
                    <p className="text-[15px] font-bold text-slate-700">{currentSite.manager}</p>
                  </div>
                  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100/50">
                    <p className="text-[10px] font-bold text-slate-400 mb-1.5 uppercase">안전 관리감독자</p>
                    <p className="text-[15px] font-bold text-slate-700">{currentSite.supervisor}</p>
                  </div>
                </div>
              </div>

              <div className="flex items-center justify-between px-2 mb-2">
                <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">관리 항목 리스트</h3>
                {currentUser?.role === 'Worker' && (
                  <span className="text-[10px] bg-[#f0f9fb] text-[#0097b2] font-bold px-2 py-0.5 rounded-full border border-[#0097b2]/10 uppercase">제한된 보기</span>
                )}
              </div>

              <div className="grid gap-3.5">
                {visibleCategories.map(cat => (
                  <button key={cat.id} onClick={() => { setActiveCategoryId(cat.id); setView('CATEGORY_DETAIL'); }} className="w-full flex items-center justify-between p-6 bg-white rounded-[2rem] shadow-sm border border-slate-100 hover:border-[#0097b2]/40 hover:shadow-xl hover:shadow-slate-200/40 transition-all active:scale-[0.99] group">
                    <div className="flex items-center gap-5">
                      <div className="p-3 bg-slate-50 rounded-2xl group-hover:bg-[#f0f9fb] transition-colors">
                        <FileText size={22} className="text-slate-400 group-hover:text-[#0097b2]" />
                      </div>
                      <span className="font-bold text-slate-700 text-lg group-hover:text-[#0097b2] transition-colors tracking-tight">{cat.name}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      {(cat.files.length + (cat.reports?.length || 0)) > 0 && (
                        <span className="bg-[#0097b2] text-white text-[10px] font-extrabold px-2.5 py-1 rounded-full shadow-lg shadow-[#0097b2]/20">
                          {cat.files.length + (cat.reports?.length || 0)}
                        </span>
                      )}
                      <ChevronRight size={22} className="text-slate-300 group-hover:text-[#0097b2] group-hover:translate-x-1 transition-all" />
                    </div>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 py-20">
              <Building2 size={72} className="mb-6 opacity-10" />
              <p className="font-bold text-lg">등록된 현장이 없습니다.</p>
              {currentUser?.role === 'Admin' && (
                <button onClick={() => setView('ADD_SITE')} className="mt-8 bg-[#0097b2] text-white px-10 py-5 rounded-[2rem] font-bold shadow-2xl shadow-[#0097b2]/30 active:scale-95 transition-all hover:bg-[#008199]">새 현장 등록하기</button>
              )}
            </div>
          )}
        </div>
      </div>
    );
  };

  const ReportFormScreen = () => {
    const [type, setType] = useState<'위험발굴' | '작업중지'>('위험발굴');
    const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
    const [issue, setIssue] = useState('');
    const [action, setAction] = useState('');
    const [image, setImage] = useState<string | null>(null);

    const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) setImage(URL.createObjectURL(file));
    };

    return (
      <div className="h-screen bg-white flex flex-col overflow-hidden">
        <div className="flex items-center p-5 border-b border-slate-100 shrink-0">
          <button onClick={() => setView('CATEGORY_DETAIL')} className="p-2.5 -ml-2 text-slate-400 hover:text-[#0097b2] rounded-2xl">
            <X size={24}/>
          </button>
          <h2 className="text-xl font-bold ml-2 text-slate-800 tracking-tight">안전 활동 등록</h2>
        </div>
        <div className="flex-1 overflow-y-auto p-6 space-y-6 max-w-lg mx-auto w-full">
          <div>
            <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-3">유형 선택</label>
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setType('위험발굴')} className={`flex items-center justify-center gap-2 py-4 rounded-2xl font-bold transition-all border-2 ${type === '위험발굴' ? 'border-[#0097b2] bg-[#f0f9fb] text-[#0097b2]' : 'border-slate-50 text-slate-400'}`}>
                <AlertTriangle size={20}/> 위험발굴
              </button>
              <button onClick={() => setType('작업중지')} className={`flex items-center justify-center gap-2 py-4 rounded-2xl font-bold transition-all border-2 ${type === '작업중지' ? 'border-red-500 bg-red-50 text-red-500' : 'border-slate-50 text-slate-400'}`}>
                <Zap size={20}/> 작업중지
              </button>
            </div>
          </div>
          <div>
            <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">날짜</label>
            <div className="relative">
              <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18}/>
              <input type="date" className="w-full p-4 pl-12 bg-slate-50 border border-slate-100 rounded-2xl focus:outline-none focus:border-[#0097b2]" value={date} onChange={e => setDate(e.target.value)} />
            </div>
          </div>
          <div>
            <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">부적합 내용</label>
            <textarea className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl focus:outline-none focus:border-[#0097b2] min-h-[100px]" placeholder="발견된 위험 요소나 부적합 사항을 입력하세요" value={issue} onChange={e => setIssue(e.target.value)} />
          </div>
          <div>
            <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">조치 내용</label>
            <textarea className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl focus:outline-none focus:border-[#0097b2] min-h-[100px]" placeholder="수행된 또는 필요한 조치 사항을 입력하세요" value={action} onChange={e => setAction(e.target.value)} />
          </div>
          <div>
            <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">사진 추가</label>
            <label className="w-full h-40 border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-[#0097b2] hover:bg-[#f0f9fb] transition-all overflow-hidden">
              {image ? (
                <img src={image} className="w-full h-full object-cover" alt="Uploaded" />
              ) : (
                <>
                  <Camera size={32} className="text-slate-300 mb-2" />
                  <span className="text-sm font-bold text-slate-400">사진 등록하기</span>
                </>
              )}
              <input type="file" accept="image/*" className="hidden" onChange={handleImageChange} />
            </label>
          </div>
          <button onClick={() => handleReportSubmit({ type, date, issue, action, imageUrl: image || undefined })} className="w-full bg-[#0097b2] text-white p-5 rounded-3xl font-bold shadow-xl shadow-[#0097b2]/20 active:scale-95 transition-all text-lg">등록 완료</button>
        </div>
      </div>
    );
  };

  const CategoryDetailScreen = () => {
    const site = sites.find(s => s.id === activeSiteId);
    const category = site?.categories.find(c => c.id === activeCategoryId);
    const isSafetyCategory = category?.name === '위험발굴/작업중지';

    if (!category) return null;

    return (
      <div className="h-screen bg-slate-50 flex flex-col">
        <div className="bg-white border-b border-slate-200 p-5 flex items-center justify-between shrink-0 sticky top-0 z-10">
          <div className="flex items-center min-w-0">
            <button onClick={() => setView('SITES')} className="p-2.5 -ml-2 text-slate-400 hover:text-[#0097b2] rounded-2xl">
              <ArrowLeft size={24}/>
            </button>
            <div className="ml-3 min-w-0">
              <h2 className="text-xl font-bold text-slate-900 leading-none truncate tracking-tight">{category.name}</h2>
              <p className="text-[10px] font-bold text-[#0097b2] mt-1.5 uppercase tracking-widest truncate">{site?.name}</p>
            </div>
          </div>
          <div className="flex gap-2">
            {isSafetyCategory ? (
              <button onClick={() => setView('REPORT_FORM')} className="bg-[#0097b2] text-white px-5 py-3 rounded-2xl shadow-lg shadow-[#0097b2]/20 font-bold flex items-center gap-2 hover:bg-[#008199] active:scale-95 transition-all">
                <Plus size={20}/> 등록하기
              </button>
            ) : (
              <label className="bg-[#0097b2] text-white p-3 rounded-[1.25rem] shadow-xl shadow-[#0097b2]/20 cursor-pointer active:scale-90 transition-all hover:bg-[#008199]">
                <FileUp size={24} />
                <input type="file" multiple className="hidden" onChange={handleFileUpload} />
              </label>
            )}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          {(!category.files.length && !(category.reports?.length)) ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300 py-20">
              <div className="bg-white p-10 rounded-[3rem] shadow-sm mb-6 border border-slate-50">
                <ClipboardList size={64} className="text-[#0097b2] opacity-20" />
              </div>
              <p className="font-bold text-slate-400 text-lg">등록된 데이터가 없습니다</p>
              <p className="text-xs mt-2 font-semibold text-slate-400 bg-slate-200/50 px-4 py-1.5 rounded-full uppercase tracking-tighter">
                {isSafetyCategory ? '상단의 등록하기 버튼을 눌러주세요' : '파일을 추가하여 관리를 시작하세요'}
              </p>
            </div>
          ) : (
            <div className="max-w-3xl mx-auto space-y-4">
              {/* Structured Reports Render */}
              {category.reports?.map(report => (
                <div key={report.id} className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 space-y-4">
                  <div className="flex justify-between items-start">
                    <div className="flex items-center gap-2">
                      <span className={`px-3 py-1 rounded-full text-[11px] font-extrabold uppercase ${report.type === '위험발굴' ? 'bg-[#f0f9fb] text-[#0097b2]' : 'bg-red-50 text-red-500'}`}>
                        {report.type}
                      </span>
                      <span className="text-sm font-bold text-slate-400">{report.date}</span>
                    </div>
                    <button onClick={() => deleteItem(report.id, 'report')} className="p-2 text-slate-200 hover:text-red-500 transition-colors">
                      <Trash2 size={18}/>
                    </button>
                  </div>
                  <div className="grid md:grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">부적합 내용</p>
                      <p className="text-[15px] font-medium text-slate-800 leading-relaxed">{report.issue}</p>
                    </div>
                    <div className="space-y-1">
                      <p className="text-[10px] font-bold text-[#0097b2] uppercase tracking-widest">조치 내용</p>
                      <p className="text-[15px] font-medium text-slate-800 leading-relaxed">{report.action}</p>
                    </div>
                  </div>
                  {report.imageUrl && (
                    <div className="w-full h-48 rounded-2xl overflow-hidden bg-slate-100">
                      <img src={report.imageUrl} className="w-full h-full object-cover" alt="Report Attachment" />
                    </div>
                  )}
                  <div className="pt-3 border-t border-slate-50 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className="text-[9px] font-bold text-white bg-slate-400 px-2 py-0.5 rounded-full uppercase">
                        {report.uploaderRole === 'Admin' ? '관리자' : '근로자'}
                      </span>
                      <span className="text-[11px] font-bold text-slate-500">{report.uploadedBy}</span>
                    </div>
                    <span className="text-[10px] text-slate-300">{report.uploadedAt}</span>
                  </div>
                </div>
              ))}

              {/* Files Render */}
              {category.files.map(file => (
                <div key={file.id} className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-100 flex items-center justify-between group hover:border-[#0097b2]/40 transition-all">
                  <div className="flex items-center gap-4 overflow-hidden">
                    <div className="shrink-0 w-14 h-14 flex items-center justify-center bg-slate-50 rounded-[1.25rem] group-hover:bg-[#f0f9fb] transition-colors overflow-hidden border border-slate-50">
                      {file.type.includes('image') ? <img src={file.url} className="w-full h-full object-cover" alt="Preview" /> : 
                       file.type.includes('sheet') ? <FileSpreadsheet size={24} className="text-green-600" /> : <FileText size={24} className="text-slate-400" />}
                    </div>
                    <div className="overflow-hidden">
                      <p className="text-[15px] font-bold text-slate-800 truncate leading-tight mb-2 tracking-tight">{file.name}</p>
                      <div className="flex flex-wrap items-center gap-x-2 gap-y-1">
                        <span className="text-[9px] font-extrabold text-white bg-[#0097b2] px-2 py-0.5 rounded-full uppercase tracking-tighter">{file.uploaderRole === 'Admin' ? '관리자' : '근로자'}</span>
                        <span className="text-[11px] font-bold text-slate-600">{file.uploadedBy}</span>
                        <span className="text-slate-200 text-xs">•</span>
                        <span className="text-[11px] text-slate-400 font-medium">{file.uploadedAt}</span>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-2 shrink-0 ml-4">
                    <a href={file.url} download={file.name} className="p-3 text-[#0097b2] hover:bg-[#f0f9fb] rounded-2xl transition-all" title="다운로드"><Download size={20} /></a>
                    {(currentUser?.role === 'Admin' || currentUser?.name === file.uploadedBy) && (
                      <button onClick={() => deleteItem(file.id, 'file')} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-2xl transition-all" title="삭제"><Trash2 size={20} /></button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    );
  };

  if (view === 'AUTH') return <AuthScreen />;
  if (view === 'ADD_SITE') return <AddSiteScreen />;
  if (view === 'REPORT_FORM') return <ReportFormScreen />;
  if (view === 'CATEGORY_DETAIL') return <CategoryDetailScreen />;
  return <SiteTabsScreen />;
}

export const DEFAULT_CATEGORIES = [
  'GSA', 
  'GSB', 
  'GSC', 
  'GSD', 
  'GSE', 
  'GEF', 
  'GSG', 
  '현장 안전 점검', 
  '위험발굴/작업중지'
];

export const INITIAL_SITES = [
  {
    id: '1',
    name: '서울 테헤란로 현장',
    manager: '김철수',
    supervisor: '이영희',
    categories: DEFAULT_CATEGORIES.map(name => ({ 
      id: Math.random().toString(36).substr(2, 9), 
      name, 
      files: [],
      reports: []
    }))
  },
  {
    id: '2',
    name: '부산 해운대 현장',
    manager: '박지성',
    supervisor: '최민수',
    categories: DEFAULT_CATEGORIES.map(name => ({ 
      id: Math.random().toString(36).substr(2, 9), 
      name, 
      files: [],
      reports: []
    }))
  }
];

import React, { useState } from 'react';
import { User, UserRole, ConstructionSite, SiteCategory, UploadedFile, SafetyReport } from './types';
import { INITIAL_SITES, DEFAULT_CATEGORIES } from './constants';
import { 
  Plus, 
  ChevronRight, 
  FileUp, 
  LogOut, 
  Building2, 
  X, 
  FileText, 
  Image as ImageIcon, 
  FileSpreadsheet,
  ArrowLeft,
  Download,
  Trash2,
  ShieldCheck,
  User as UserIcon,
  Share2,
  Check,
  ClipboardList,
  Calendar,
  AlertTriangle,
  Zap,
  Camera
} from 'lucide-react';

// --- Types of Views ---
type ViewState = 'AUTH' | 'SITES' | 'ADD_SITE' | 'MENU' | 'CATEGORY_DETAIL' | 'REPORT_FORM';

const PRIMARY_TEAL = '#0097b2';
const LOGO_URL = 'https://raw.githubusercontent.com/t-park/everscape-logo/main/everscape_logo.png';

export default function App() {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('AUTH');
  const [sites, setSites] = useState<ConstructionSite[]>(INITIAL_SITES);
  const [activeSiteId, setActiveSiteId] = useState<string | null>(null);
  const [activeCategoryId, setActiveCategoryId] = useState<string | null>(null);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setView('SITES');
    if (sites.length > 0) setActiveSiteId(sites[0].id);
  };

  const addSite = (name: string, manager: string, supervisor: string) => {
    const newSite: ConstructionSite = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      manager,
      supervisor,
      categories: DEFAULT_CATEGORIES.map(catName => ({
        id: Math.random().toString(36).substr(2, 9),
        name: catName,
        files: [],
        reports: []
      }))
    };
    setSites([...sites, newSite]);
    setActiveSiteId(newSite.id);
    setView('SITES');
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || !activeSiteId || !activeCategoryId || !currentUser) return;

    const newFiles: UploadedFile[] = Array.from(files).map((file: File) => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      type: file.type,
      size: file.size,
      uploadedAt: new Date().toLocaleString('ko-KR'),
      uploadedBy: currentUser.name,
      uploaderRole: currentUser.role,
      url: URL.createObjectURL(file)
    }));

    updateSitesData(activeSiteId, activeCategoryId, (cat) => ({
      ...cat,
      files: [...cat.files, ...newFiles]
    }));
  };

  const handleReportSubmit = (report: Omit<SafetyReport, 'id' | 'uploadedAt' | 'uploadedBy' | 'uploaderRole'>) => {
    if (!activeSiteId || !activeCategoryId || !currentUser) return;

    const newReport: SafetyReport = {
      ...report,
      id: Math.random().toString(36).substr(2, 9),
      uploadedAt: new Date().toLocaleString('ko-KR'),
      uploadedBy: currentUser.name,
      uploaderRole: currentUser.role
    };

    updateSitesData(activeSiteId, activeCategoryId, (cat) => ({
      ...cat,
      reports: [...(cat.reports || []), newReport]
    }));
    setView('CATEGORY_DETAIL');
  };

  const updateSitesData = (siteId: string, catId: string, updateFn: (cat: SiteCategory) => SiteCategory) => {
    setSites(prev => prev.map(site => {
      if (site.id !== siteId) return site;
      return {
        ...site,
        categories: site.categories.map(cat => {
          if (cat.id !== catId) return cat;
          return updateFn(cat);
        })
      };
    }));
  };

  const deleteItem = (id: string, type: 'file' | 'report') => {
    if (!activeSiteId || !activeCategoryId) return;
    updateSitesData(activeSiteId, activeCategoryId, (cat) => ({
      ...cat,
      files: type === 'file' ? cat.files.filter(f => f.id !== id) : cat.files,
      reports: type === 'report' ? (cat.reports || []).filter(r => r.id !== id) : (cat.reports || [])
    }));
  };

  // --- Sub-Components ---

  const AuthScreen = () => {
    const [isReg, setIsReg] = useState(false);
    const [role, setRole] = useState<UserRole>('Worker');
    const [name, setName] = useState('');
    const [shared, setShared] = useState(false);

    const handleShare = async () => {
      const shareData = {
        title: 'GSS 안전관리 - 에버스케이프',
        text: '건설 현장 맞춤형 스마트 안전 솔루션, GSS 안전관리 앱을 확인해보세요.',
        url: window.location.href,
      };
      try {
        if (navigator.share) await navigator.share(shareData);
        else {
          await navigator.clipboard.writeText(window.location.href);
          setShared(true);
          setTimeout(() => setShared(false), 2000);
        }
      } catch (err) { console.error('Error sharing:', err); }
    };

    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
        <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 shadow-2xl shadow-slate-200/60 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-full mb-8 flex justify-center">
              <img src={LOGO_URL} alt="Everscape Logo" className="h-14 object-contain" onError={(e) => { e.currentTarget.src = "https://api.iconify.design/logos:everscale.svg"; }} />
            </div>
            <h1 className="text-2xl font-bold text-slate-800 tracking-tight">GSS 안전관리</h1>
            <p className="text-slate-400 mt-2 text-sm font-medium">현장 맞춤형 스마트 안전 솔루션</p>
          </div>
          <div className="space-y-6">
            <div>
              <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-3">사용자 유형 선택</label>
              <div className="grid grid-cols-2 gap-3">
                <button onClick={() => setRole('Worker')} className={`flex flex-col items-center justify-center gap-2 py-4 rounded-3xl font-bold text-sm transition-all border-2 ${role === 'Worker' ? 'border-[#0097b2] bg-[#f0f9fb] text-[#0097b2]' : 'border-slate-50 bg-slate-50 text-slate-400'}`}>
                  <UserIcon size={24} />
                  <span>근로자용</span>
                </button>
                <button onClick={() => setRole('Admin')} className={`flex flex-col items-center justify-center gap-2 py-4 rounded-3xl font-bold text-sm transition-all border-2 ${role === 'Admin' ? 'border-[#0097b2] bg-[#f0f9fb] text-[#0097b2]' : 'border-slate-50 bg-slate-50 text-slate-400'}`}>
                  <ShieldCheck size={24} />
                  <span>관리자용</span>
                </button>
              </div>
            </div>
            <div className="space-y-4">
              <div className="group">
                <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">성함</label>
                <input type="text" placeholder="이름을 입력하세요" className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all" value={name} onChange={(e) => setName(e.target.value)} />
              </div>
              <div>
                <label className="text-[11px] font-bold text-slate-400 ml-1 uppercase tracking-widest block mb-2">비밀번호</label>
                <input type="password" placeholder="비밀번호를 입력하세요" className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 focus:outline-none focus:border-[#0097b2] focus:ring-4 focus:ring-[#0097b2]/5 transition-all" />
              </div>
            </div>
            <button onClick={() => handleLogin({ id: Math.random().toString(36).substr(2, 9), name: name || '사용자', role, email: 'user@gss.com' })} className="w-full bg-[#0097b2] text-white p-5 rounded-3xl font-bold shadow-xl shadow-[#0097b2]/20 active:scale-[0.98] transition-all mt-4 hover:bg-[#008199]">
              {isReg ? '회원가입 완료' : '로그인'}
            </button>
            <div className="pt-2 text-center">
              <button onClick={() => setIsReg(!isReg)} className="text-slate-400 text-xs font-semibold py-2">
                {isReg ? '이미 계정이 있으신가요? 로그인' : '처음 방문하셨나요? 계정 만들기'}
              </button>
            </div>
            <div className="pt-4 border-t border-slate-100">
              <p className="text-center text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-3">어플 공유하기</p>
              <button onClick={handleShare} className="w-full flex items-center justify-center gap-2 py-3 rounded-2xl border-2 border-slate-100 text-slate-600 font-bold text-sm hover:bg-slate-50 transition-all active:scale-95">
                {shared ? <Check size={18} className="text-[#0097b2]" /> : <Share2 size={18} />}
                {shared ? '링크가 복사되었습니다' : '동료에게 어플 공유하기'}
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  };

  const SiteTabsScreen = () => {
    const currentSite = sites.find(s => s.id === activeSiteId);
    const visibleCategories = currentSite?.categories.filter(cat => {
      if (currentUser?.role === 'Admin') return true;
      return cat.name === '현장 안전 점검' || cat.name === '위험발굴/작업중지';
    }) || [];

    return (
      <div className="flex flex-col h-screen bg-[#fafbfc]">
        <div className="bg-white text-slate-800 px-5 pt-6 shrink-0 shadow-sm border-b border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <div className="flex items-center gap-3">
              <img src={LOGO_URL} alt="Logo" className="h-7 object-contain" onError={(e) => e.currentTarget.style.display = 'none'} />
              <div className="h-4 w-px bg-slate-200" />
              <h1 className="text-lg font-extrabold text-[#0097b2] tracking-tight">GSS 안전관리</h1>
            </div>
            <div className="flex items-center gap-3">
               <div className="text-right hidden sm:block">
                  <p className="text-[10px] font-bold text-[#0097b2] leading-none uppercase tracking-tighter mb-0.5">{currentUser?.role === 'Admin' ? 'SITE ADMIN' : 'WORKER'}</p>
                  <p className="text-sm font-bold text-slate-800">{currentUser?.name}</p>
               </div>
               <button onClick={() => setCurrentUser(null)} className="p-2.5 bg-slate-50 hover:bg-red-50 hover:text-red-500 rounded-2xl transition-all text-slate-400">
                 <LogOut size={20}/>
               </button>
            </div>
          </div>
          <div className="flex overflow-x-auto no-scrollbar gap-8 items-center">
            {sites.map(site => (
              <button key={site.id} onClick={() => setActiveSiteId(site.id)} className={`py-4 px-1 font-bold whitespace-nowrap transition-all relative text-sm tracking-tight ${activeSiteId === site.id ? 'text-[#0097b2]' : 'text-slate-400'}`}>
                {site.name}
                {activeSiteId === site.id && <div className="absolute bottom-0 left-0 right-0 h-1 bg-[#0097b2] rounded-t-full shadow-[0_-2px_6px_rgba(0,151,178,0.3)]" />}
              </button>
            ))}
            {currentUser?.role === 'Admin' && (
              <button onClick={() => setView('ADD_SITE')} className="flex items-center gap-1.5 py-4 px-1 text-[#0097b2] font-bold whitespace-nowrap text-sm opacity-60 hover:opacity-100 transition-opacity">
                <Plus size={16} /> 현장 추가
              </button>
            )}
          </div>
