              <p className="font-bold text-lg">등록된 현장이 없습니다.</p>
              {currentUser?.role === 'Admin' && (
                <button onClick={() => setView('ADD_SITE')} className="mt-8 bg-[#0097b2] text-white px-10 py-5 rounded-[2rem] font-bold shadow-2xl shadow-[#0097b2]/30 active:scale-95 transition-all hover:bg-[#008199]">새 현장 등록하기</button>
